  // 各神話のシンボル画（hub のタイル用）
  function drawPantheonSymbol(ctx, W, H, cx, cy, t, key, accent) {
    // 共通：背景グラデ
    const bg = ctx.createLinearGradient(0, 0, 0, H);
    bg.addColorStop(0, '#0a0418'); bg.addColorStop(0.5, accent + '40'); bg.addColorStop(1, '#0a0418');
    ctx.fillStyle = bg; ctx.fillRect(0, 0, W, H);
    // 共通：背景の星屑
    for (let i = 0; i < 30; i++) {
      const sx = (i * 137 % W);
      const sy = (i * 89 % (H - 80));
      ctx.fillStyle = '#ffffff' + (Math.floor(60 + Math.sin(t + i) * 60).toString(16).padStart(2, '0'));
      ctx.fillRect(sx, sy, 1.5, 1.5);
    }
    ctx.save();
    ctx.translate(cx, cy);

    if (key === 'genesis') {
      // 創世記：天地創造の光と闇 + 命の樹
      // 光の球（神の眼）
      const r = 80 + Math.sin(t * 0.6) * 6;
      const grd = ctx.createRadialGradient(0, -30, 5, 0, -30, r);
      grd.addColorStop(0, '#ffffff'); grd.addColorStop(0.3, '#fff8c0');
      grd.addColorStop(0.7, accent + '99'); grd.addColorStop(1, accent + '00');
      ctx.fillStyle = grd;
      ctx.beginPath(); ctx.arc(0, -30, r, 0, Math.PI * 2); ctx.fill();
      // 命の樹（シンプルなシルエット）
      ctx.strokeStyle = '#3a2814'; ctx.lineWidth = 6;
      ctx.beginPath(); ctx.moveTo(0, 50); ctx.lineTo(0, 130); ctx.stroke();
      ctx.fillStyle = '#3a6a28';
      ctx.beginPath(); ctx.arc(0, 50, 40, 0, Math.PI * 2); ctx.fill();
      ctx.fillStyle = '#5a8a38';
      ctx.beginPath(); ctx.arc(-20, 30, 25, 0, Math.PI * 2); ctx.fill();
      ctx.beginPath(); ctx.arc(20, 25, 28, 0, Math.PI * 2); ctx.fill();
      // リンゴ
      ctx.fillStyle = '#c01828';
      [[-15,40],[12,55],[8,28]].forEach(([x,y]) => {
        ctx.beginPath(); ctx.arc(x, y, 4, 0, Math.PI * 2); ctx.fill();
      });
    } else if (key === 'greek') {
      // ギリシャ：ゼウスの稲妻 + 神殿の柱
      ctx.fillStyle = '#e0d8b0';
      // 神殿の柱（3本）
      [-60, 0, 60].forEach(x => {
        ctx.fillRect(x - 8, -80, 16, 140);
        ctx.fillRect(x - 14, -90, 28, 12);
        ctx.fillRect(x - 14, 60, 28, 12);
      });
      // ペディメント
      ctx.beginPath();
      ctx.moveTo(-80, -90); ctx.lineTo(0, -120); ctx.lineTo(80, -90); ctx.closePath();
      ctx.fill();
      // 稲妻（ゼウス）
      ctx.fillStyle = '#fff8c0';
      ctx.shadowColor = accent; ctx.shadowBlur = 20;
      ctx.beginPath();
      ctx.moveTo(0, -100);
      ctx.lineTo(-15, -40); ctx.lineTo(-5, -40);
      ctx.lineTo(-20, 30); ctx.lineTo(0, -10); ctx.lineTo(-10, -10);
      ctx.lineTo(10, -80); ctx.closePath();
      ctx.fill();
      ctx.shadowBlur = 0;
    } else if (key === 'japan') {
      // 日本：鳥居 + 太陽 + 桜
      // 太陽（赤い円）
      const sun = 70 + Math.sin(t * 0.8) * 4;
      const sg = ctx.createRadialGradient(0, -40, 0, 0, -40, sun);
      sg.addColorStop(0, '#ffffff'); sg.addColorStop(0.5, '#ff8060'); sg.addColorStop(1, '#c02020');
      ctx.fillStyle = sg;
      ctx.beginPath(); ctx.arc(0, -40, sun, 0, Math.PI * 2); ctx.fill();
      // 鳥居（朱色）
      ctx.fillStyle = '#c02828';
      ctx.fillRect(-70, 30, 140, 14); // 上の横木（笠木）
      ctx.fillRect(-60, 50, 120, 8);  // 下の横木（貫）
      ctx.fillRect(-60, 38, 12, 90); // 左柱
      ctx.fillRect(48, 38, 12, 90);  // 右柱
      ctx.fillStyle = '#1a0a08';
      ctx.fillRect(-78, 24, 156, 6); // 笠木の上
      // 桜の花びら（飛ぶ）
      for (let i = 0; i < 6; i++) {
        const px = (i * 60 + t * 30) % 320 - 160;
        const py = -100 + (i * 40 + t * 20) % 200;
        ctx.fillStyle = '#ffb0c8';
        ctx.beginPath(); ctx.ellipse(px, py, 6, 4, t + i, 0, Math.PI * 2); ctx.fill();
      }
    } else if (key === 'norse') {
      // 北欧：世界樹 Yggdrasil + ルーン
      // 中央の世界樹
      ctx.strokeStyle = '#5a3818'; ctx.lineWidth = 8;
      ctx.beginPath(); ctx.moveTo(0, -100); ctx.lineTo(0, 130); ctx.stroke();
      // 三つの大枝
      ctx.lineWidth = 5;
      [-1, 1].forEach(d => {
        ctx.beginPath();
        ctx.moveTo(0, -60); ctx.bezierCurveTo(d * 30, -80, d * 60, -100, d * 90, -120);
        ctx.stroke();
        ctx.beginPath();
        ctx.moveTo(0, -20); ctx.bezierCurveTo(d * 40, -30, d * 70, -40, d * 100, -60);
        ctx.stroke();
      });
      // 葉（雲のかたまり）
      ctx.fillStyle = '#3a6a48';
      [[-90,-115,30],[90,-115,30],[-100,-55,28],[100,-55,28],[0,-110,40]].forEach(([x,y,r]) => {
        ctx.beginPath(); ctx.arc(x, y, r, 0, Math.PI * 2); ctx.fill();
      });
      // 雪片＋ルーン文字
      ctx.font = 'bold 32px serif';
      ctx.textAlign = 'center'; ctx.textBaseline = 'middle';
      ctx.fillStyle = accent;
      ctx.shadowColor = accent; ctx.shadowBlur = 12;
      ['ᚠ','ᚱ','ᛞ'].forEach((rune, i) => {
        const a = i * Math.PI * 2 / 3 + t * 0.5;
        ctx.fillText(rune, Math.cos(a) * 110, 30 + Math.sin(a) * 30);
      });
      ctx.shadowBlur = 0;
    } else if (key === 'egypt') {
      // エジプト：ピラミッド + ホルスの眼
      // 太陽
      ctx.fillStyle = '#ffd040';
      ctx.shadowColor = '#ffa030'; ctx.shadowBlur = 20;
      ctx.beginPath(); ctx.arc(80, -100, 25, 0, Math.PI * 2); ctx.fill();
      ctx.shadowBlur = 0;
      // 砂漠地平
      ctx.fillStyle = '#c89060';
      ctx.fillRect(-200, 100, 400, 80);
      // ピラミッド
      ctx.fillStyle = '#a86840';
      ctx.beginPath();
      ctx.moveTo(-120, 100); ctx.lineTo(-30, -30); ctx.lineTo(60, 100); ctx.closePath();
      ctx.fill();
      ctx.fillStyle = '#7a4828';
      ctx.beginPath();
      ctx.moveTo(-30, -30); ctx.lineTo(-30, 100); ctx.lineTo(60, 100); ctx.closePath();
      ctx.fill();
      // ホルスの眼（頂上に光る）
      ctx.fillStyle = '#fff';
      ctx.beginPath();
      ctx.ellipse(-30, -10, 16, 10, 0, 0, Math.PI * 2);
      ctx.fill();
      ctx.fillStyle = accent;
      ctx.beginPath();
      ctx.arc(-30, -10, 5, 0, Math.PI * 2); ctx.fill();
      ctx.fillStyle = '#000';
      ctx.beginPath();
      ctx.arc(-30, -10, 2, 0, Math.PI * 2); ctx.fill();
    } else if (key === 'hindu') {
      // ヒンドゥー：蓮 + オーム + 三主神
      // 大蓮華
      ctx.save();
      ctx.rotate(t * 0.1);
      for (let p = 0; p < 8; p++) {
        ctx.save();
        ctx.rotate((p / 8) * Math.PI * 2);
        const lg = ctx.createLinearGradient(0, 0, 0, -100);
        lg.addColorStop(0, '#ffb0c8'); lg.addColorStop(1, '#ff60a0');
        ctx.fillStyle = lg;
        ctx.beginPath();
        ctx.moveTo(0, 0);
        ctx.bezierCurveTo(28, -30, 28, -90, 0, -110);
        ctx.bezierCurveTo(-28, -90, -28, -30, 0, 0);
        ctx.fill();
        ctx.restore();
      }
      ctx.restore();
      // オーム ॐ
      ctx.font = 'bold 100px serif';
      ctx.textAlign = 'center'; ctx.textBaseline = 'middle';
      ctx.fillStyle = '#fff';
      ctx.shadowColor = accent; ctx.shadowBlur = 25;
      ctx.fillText('ॐ', 0, -10);
      ctx.shadowBlur = 0;
    }
    ctx.restore();
  }

  async function openPantheon3D() {
    if (!window.THREE) return;
    const THREE = window.THREE;
    if (window.THREE_READY) { try { await window.THREE_READY; } catch {} }
    const ADDONS = window.THREE_ADDONS || {};

    // 👁 瞬き — 自然に目を閉じて、ゆっくり開ける
    const blink = document.createElement('div');
    blink.className = 'pantheon-blink';
    document.body.appendChild(blink);
    requestAnimationFrame(() => blink.classList.add('closing'));
    // 閉じきる（0.7s）+ 暗闇の余韻（0.3s） → シーン構築 → 開く
    await new Promise(r => setTimeout(r, 1000));

    let currentZone = 'hub'; // 'hub' (魂の宇宙) or pantheon key (神殿内部)
    const ov = document.createElement('div');
    ov.className = 'museum3d-overlay pantheon-overlay';
    ov.innerHTML = `
      <div class="museum3d-stage" id="pantheonStage"></div>
      <button class="museum3d-close" aria-label="閉じる">×</button>
      <div class="museum3d-title" id="pantheonTitle">神 殿</div>
      <div class="museum3d-info" id="pantheonInfo"></div>
      <div class="museum3d-reticle">·</div>
      <div class="museum3d-hint">WASD で歩く / ドラッグで見回す / 台座をタップ</div>
      <div class="museum3d-stick" id="ptStick"><div class="m3d-stick-knob" id="ptKnob"></div></div>
      <button class="museum3d-view-btn" id="ptViewBtn">この神殿に入る ›</button>
      <button class="pantheon-back-btn" id="ptBackBtn">← 神殿選択へ</button>
    `;
    document.body.appendChild(ov);
    requestAnimationFrame(() => ov.classList.add('open'));

    const stage = ov.querySelector('#pantheonStage');
    const titleEl = ov.querySelector('#pantheonTitle');
    const infoEl = ov.querySelector('#pantheonInfo');
    const enterBtn = ov.querySelector('#ptViewBtn');
    const backBtn = ov.querySelector('#ptBackBtn');
    const W = () => stage.clientWidth || window.innerWidth;
    const H = () => stage.clientHeight || window.innerHeight;

    const renderer = new THREE.WebGLRenderer({ antialias: true });
    renderer.setPixelRatio(Math.min(window.devicePixelRatio || 1, 1.2));
    renderer.setSize(W(), H());
    if (THREE.ACESFilmicToneMapping) renderer.toneMapping = THREE.ACESFilmicToneMapping;
    renderer.toneMappingExposure = 1.15; // 明るめ
    if ('outputColorSpace' in renderer) renderer.outputColorSpace = THREE.SRGBColorSpace;
    stage.appendChild(renderer.domElement);
    renderer.domElement.style.touchAction = 'none';

    // シーン構築（zone 切替で再構築）
    let scene, camera, plinths = [], textureCache = new Map(), composer = null, outlinePass = null;
    const animatedTextures = []; // 画像ない時の手続き的アニメ用
    let yaw = 0, pitch = -0.1;
    const keys = { w:0, a:0, s:0, d:0 };
    let stickDX = 0, stickDY = 0;
    let currentNear = null;

    // Wikimedia 画像ロード（既存美術館と同じ手法）
    function loadGodImage(url) {
      if (textureCache.has(url)) return Promise.resolve(textureCache.get(url));
      // Wikimedia API で thumburl を解決（CORS-clean な upload.wikimedia.org に直接）
      return new Promise((resolve, reject) => {
        const m = url.match(/Special:FilePath\/([^?]+)/);
        if (!m) return reject();
        const filename = decodeURIComponent(m[1]).replace(/_/g, ' ');
        const api = `https://commons.wikimedia.org/w/api.php?action=query&format=json&prop=imageinfo&iiprop=url&iiurlwidth=512&titles=${encodeURIComponent('File:' + filename)}&origin=*`;
        fetch(api).then(r => r.json()).then(d => {
          const pages = d.query?.pages || {};
          const p = Object.values(pages)[0];
          const thumb = p?.imageinfo?.[0]?.thumburl;
          if (!thumb) return reject();
          const img = new Image();
          img.crossOrigin = 'anonymous';
          img.onload = () => {
            const tex = new THREE.Texture(img);
            if ('colorSpace' in tex) tex.colorSpace = THREE.SRGBColorSpace;
            tex.needsUpdate = true;
            textureCache.set(url, tex);
            resolve(tex);
          };
          img.onerror = () => reject();
          img.src = thumb;
        }).catch(reject);
      });
    }

    function buildScene(zone) {
      // 古いシーンクリーンアップ
      if (scene) {
        scene.traverse(o => {
          if (o.material) {
            (Array.isArray(o.material) ? o.material : [o.material]).forEach(m => m.dispose && m.dispose());
          }
          if (o.geometry) o.geometry.dispose && o.geometry.dispose();
        });
      }
      plinths = [];
      animatedTextures.length = 0;
      scene = new THREE.Scene();
      // 🌌 暗黒の宇宙、星空
      scene.background = new THREE.Color(0x040218);
      // フォグは弱めに（遠くの星まで見える）
      scene.fog = new THREE.FogExp2(0x080422, 0.005);

      // 星空（Points）
      const starGeo = new THREE.BufferGeometry();
      const STARS = 2000;
      const sp = new Float32Array(STARS * 3);
      for (let i = 0; i < STARS; i++) {
        const r = 80 + Math.random() * 120;
        const th = Math.random() * Math.PI * 2;
        const ph = Math.acos(2 * Math.random() - 1);
        sp[i*3]   = Math.sin(ph) * Math.cos(th) * r;
        sp[i*3+1] = Math.cos(ph) * r;
        sp[i*3+2] = Math.sin(ph) * Math.sin(th) * r;
      }
      starGeo.setAttribute('position', new THREE.BufferAttribute(sp, 3));
      scene.add(new THREE.Points(starGeo, new THREE.PointsMaterial({
        color: 0xffffff, size: 0.4, sizeAttenuation: true,
        transparent: true, opacity: 0.9, depthWrite: false, fog: false,
      })));
      // 月
      const moon = new THREE.Mesh(
        new THREE.SphereGeometry(4, 32, 24),
        new THREE.MeshBasicMaterial({ color: 0xfff0d8, fog: false })
      );
      moon.position.set(40, 30, -60);
      scene.add(moon);
      const moonHalo = new THREE.Sprite(new THREE.SpriteMaterial({
        map: (() => {
          const c = document.createElement('canvas'); c.width = 256; c.height = 256;
          const g = c.getContext('2d');
          const grd = g.createRadialGradient(128, 128, 20, 128, 128, 128);
          grd.addColorStop(0, 'rgba(255,240,210,0.6)');
          grd.addColorStop(1, 'rgba(180,150,255,0)');
          g.fillStyle = grd; g.fillRect(0, 0, 256, 256);
          return new THREE.CanvasTexture(c);
        })(),
        transparent: true, opacity: 0.85, blending: THREE.AdditiveBlending,
        depthWrite: false, fog: false,
      }));
      moonHalo.position.copy(moon.position);
      moonHalo.scale.set(20, 20, 20);
      scene.add(moonHalo);

      // ╔════════════════════════════════════════════╗
      // ║ HUB と神殿内ゾーンで分岐 — HUB は魂の宇宙   ║
      // ╚════════════════════════════════════════════╝
      if (zone !== 'hub') {
      // 神殿は空に浮かぶ → 床下に雲を浮かべる
      const cloudTex = (() => {
        const c = document.createElement('canvas'); c.width = 512; c.height = 256;
        const g = c.getContext('2d');
        for (let i = 0; i < 30; i++) {
          const x = Math.random() * 512, y = 50 + Math.random() * 156;
          const r = 60 + Math.random() * 100;
          const grd = g.createRadialGradient(x, y, 0, x, y, r);
          grd.addColorStop(0, 'rgba(220,200,255,0.55)');
          grd.addColorStop(1, 'rgba(180,150,220,0)');
          g.fillStyle = grd;
          g.beginPath(); g.ellipse(x, y, r, r * 0.4, 0, 0, Math.PI*2); g.fill();
        }
        return new THREE.CanvasTexture(c);
      })();
      for (let k = 0; k < 4; k++) {
        const cloud = new THREE.Mesh(
          new THREE.PlaneGeometry(120, 60),
          new THREE.MeshBasicMaterial({ map: cloudTex, transparent: true, opacity: 0.55, depthWrite: false, fog: false })
        );
        cloud.rotation.x = -Math.PI / 2;
        cloud.position.set((Math.random() - 0.5) * 40, -8 - k * 3, (Math.random() - 0.5) * 40);
        scene.add(cloud);
      }

      // 🌃 眼下の街（雲のさらに下に夜景）— 詩的な夜景
      // 街の地表（高解像度・有機的な道路網 + 街灯の星雲）
      const groundTex = (() => {
        const c = document.createElement('canvas'); c.width = 2048; c.height = 2048;
        const g = c.getContext('2d');
        // 深い藍のベース（中心から放射）
        const grd = g.createRadialGradient(1024, 1024, 200, 1024, 1024, 1100);
        grd.addColorStop(0, '#0a142a'); grd.addColorStop(0.5, '#04081a'); grd.addColorStop(1, '#010206');
        g.fillStyle = grd; g.fillRect(0, 0, 2048, 2048);
        // 細かい道路グリッド（街区）
        g.strokeStyle = 'rgba(255,200,120,0.06)';
        g.lineWidth = 1;
        for (let i = 0; i <= 64; i++) {
          g.beginPath(); g.moveTo(i * 32, 0); g.lineTo(i * 32, 2048); g.stroke();
          g.beginPath(); g.moveTo(0, i * 32); g.lineTo(2048, i * 32); g.stroke();
        }
        // 中規模道路（光る）
        g.strokeStyle = 'rgba(255,210,140,0.18)';
        g.lineWidth = 2.5;
        for (let i = 0; i <= 16; i++) {
          g.beginPath(); g.moveTo(i * 128, 0); g.lineTo(i * 128, 2048); g.stroke();
          g.beginPath(); g.moveTo(0, i * 128); g.lineTo(2048, i * 128); g.stroke();
        }
        // 大通り（主要道路 — 都市の動脈）
        g.strokeStyle = 'rgba(255,235,170,0.42)';
        g.lineWidth = 6;
        for (let i = 0; i < 6; i++) {
          const p = 200 + i * 320;
          g.beginPath(); g.moveTo(0, p); g.lineTo(2048, p); g.stroke();
          g.beginPath(); g.moveTo(p, 0); g.lineTo(p, 2048); g.stroke();
        }
        // 川（曲線）
        g.strokeStyle = 'rgba(120,160,220,0.5)';
        g.lineWidth = 18;
        g.beginPath();
        g.moveTo(0, 1300);
        g.bezierCurveTo(500, 1100, 1000, 1500, 1500, 1200);
        g.bezierCurveTo(1800, 1050, 2000, 1300, 2048, 1100);
        g.stroke();
        // 川の輝き（月光反射）
        g.strokeStyle = 'rgba(220,230,255,0.25)';
        g.lineWidth = 10;
        g.beginPath();
        g.moveTo(0, 1300);
        g.bezierCurveTo(500, 1100, 1000, 1500, 1500, 1200);
        g.bezierCurveTo(1800, 1050, 2000, 1300, 2048, 1100);
        g.stroke();
        // 街灯のドット（密度の濃淡で都市らしさ）
        for (let i = 0; i < 2200; i++) {
          const cx = 1024, cy = 1024;
          const r = Math.sqrt(Math.random()) * 900;
          const a = Math.random() * Math.PI * 2;
          const x = cx + Math.cos(a) * r;
          const y = cy + Math.sin(a) * r;
          const colors = ['rgba(255,220,160,0.8)', 'rgba(255,200,120,0.7)', 'rgba(220,200,255,0.5)', 'rgba(255,180,80,0.6)'];
          g.fillStyle = colors[i % 4];
          g.fillRect(x, y, 1.5, 1.5);
        }
        // 公園・広場の暗いパッチ（5つ）
        for (let i = 0; i < 5; i++) {
          const x = 200 + Math.random() * 1600;
          const y = 200 + Math.random() * 1600;
          const r = 50 + Math.random() * 80;
          const grd2 = g.createRadialGradient(x, y, 0, x, y, r);
          grd2.addColorStop(0, 'rgba(8,12,8,0.7)');
          grd2.addColorStop(1, 'rgba(8,12,8,0)');
          g.fillStyle = grd2;
          g.beginPath(); g.arc(x, y, r, 0, Math.PI*2); g.fill();
        }
        return new THREE.CanvasTexture(c);
      })();
      const cityGround = new THREE.Mesh(
        new THREE.CircleGeometry(200, 64),
        new THREE.MeshBasicMaterial({ map: groundTex, fog: false })
      );
      cityGround.rotation.x = -Math.PI / 2;
      cityGround.position.y = -55;
      scene.add(cityGround);

      // 🌊 港（片側に水面 — 月光が反射）
      const harborTex = (() => {
        const c = document.createElement('canvas'); c.width = 512; c.height = 512;
        const g = c.getContext('2d');
        const grd = g.createLinearGradient(0, 0, 0, 512);
        grd.addColorStop(0, '#0a1830'); grd.addColorStop(1, '#02060e');
        g.fillStyle = grd; g.fillRect(0, 0, 512, 512);
        // 月の反射（縦の光の帯）
        g.fillStyle = 'rgba(220,200,255,0.25)';
        for (let i = 0; i < 30; i++) {
          const y = 200 + i * 10;
          g.fillRect(220, y, 80 + Math.sin(i)*30, 1.5);
        }
        // 漣
        g.strokeStyle = 'rgba(180,200,255,0.15)'; g.lineWidth = 0.8;
        for (let i = 0; i < 80; i++) {
          g.beginPath();
          g.moveTo(Math.random()*512, Math.random()*512);
          g.lineTo(Math.random()*512, Math.random()*512);
          g.stroke();
        }
        return new THREE.CanvasTexture(c);
      })();
      const harbor = new THREE.Mesh(
        new THREE.PlaneGeometry(180, 100),
        new THREE.MeshBasicMaterial({ map: harborTex, fog: false, transparent: true, opacity: 0.85 })
      );
      harbor.rotation.x = -Math.PI / 2;
      harbor.position.set(140, -54.7, 0);
      scene.add(harbor);

      // 🏙 ビル群（複数ジオメトリ + 詳細）
      const BLD_BOX = 180, BLD_CYL = 30, BLD_TOWER = 12;
      const bldBoxGeo = new THREE.BoxGeometry(1, 1, 1);
      const bldCylGeo = new THREE.CylinderGeometry(0.5, 0.5, 1, 12);
      const bldMat = new THREE.MeshBasicMaterial({ color: 0x0a0a18, fog: false });
      const buildingsBox = new THREE.InstancedMesh(bldBoxGeo, bldMat, BLD_BOX);
      const buildingsCyl = new THREE.InstancedMesh(bldCylGeo, bldMat, BLD_CYL);
      const bdummy = new THREE.Object3D();
      // 窓の発光用 InstancedMesh
      const winGeo = new THREE.PlaneGeometry(0.85, 0.85);
      const winMat = new THREE.MeshBasicMaterial({ color: 0xffe8a0, fog: false, transparent: true, opacity: 0.85 });
      const windows = new THREE.InstancedMesh(winGeo, winMat, BLD_BOX);
      const wdummy = new THREE.Object3D();

      function inHarbor(x, z) {
        return x > 60 && Math.abs(z) < 50;
      }

      // 矩形ビル
      for (let i = 0; i < BLD_BOX; i++) {
        let x, z, tries = 0;
        do {
          const a = (i / BLD_BOX) * Math.PI * 2 + Math.random() * 0.5;
          const r = 30 + Math.random() * 130;
          x = Math.cos(a) * r + (Math.random() - 0.5) * 10;
          z = Math.sin(a) * r + (Math.random() - 0.5) * 10;
          tries++;
        } while (inHarbor(x, z) && tries < 5);
        const w = 1.5 + Math.random() * 2.8;
        const h = 4 + Math.random() * 22;
        const d = 1.5 + Math.random() * 2.8;
        bdummy.position.set(x, -55 + h / 2, z);
        bdummy.scale.set(w, h, d);
        bdummy.updateMatrix();
        buildingsBox.setMatrixAt(i, bdummy.matrix);
        const winColors = [0xfff0a0, 0xffd070, 0xc8e0ff, 0xffe890, 0xf0d8b0];
        const col = new THREE.Color(winColors[i % winColors.length]);
        // ランダムに消灯（夜らしさ）
        if (Math.random() < 0.18) col.multiplyScalar(0.0);
        windows.setColorAt(i, col);
        wdummy.position.set(x, -55 + h / 2, z);
        wdummy.lookAt(0, wdummy.position.y, 0);
        wdummy.scale.set(w * 0.95, h * 0.95, 1);
        wdummy.translateZ(d / 2 + 0.01);
        wdummy.updateMatrix();
        windows.setMatrixAt(i, wdummy.matrix);
      }
      buildingsBox.instanceMatrix.needsUpdate = true;
      windows.instanceMatrix.needsUpdate = true;
      if (windows.instanceColor) windows.instanceColor.needsUpdate = true;
      scene.add(buildingsBox); scene.add(windows);

      // 円筒ビル（タワー風）
      for (let i = 0; i < BLD_CYL; i++) {
        let x, z, tries = 0;
        do {
          const a = Math.random() * Math.PI * 2;
          const r = 35 + Math.random() * 110;
          x = Math.cos(a) * r;
          z = Math.sin(a) * r;
          tries++;
        } while (inHarbor(x, z) && tries < 5);
        const rad = 1.0 + Math.random() * 1.6;
        const h = 8 + Math.random() * 18;
        bdummy.position.set(x, -55 + h / 2, z);
        bdummy.scale.set(rad, h, rad);
        bdummy.updateMatrix();
        buildingsCyl.setMatrixAt(i, bdummy.matrix);
      }
      buildingsCyl.instanceMatrix.needsUpdate = true;
      scene.add(buildingsCyl);

      // 🗼 ランドマーク（高層タワー＋赤い航空灯）
      for (let i = 0; i < BLD_TOWER; i++) {
        const a = Math.random() * Math.PI * 2;
        const r = 50 + Math.random() * 80;
        const x = Math.cos(a) * r, z = Math.sin(a) * r;
        if (inHarbor(x, z)) { i--; continue; }
        const h = 28 + Math.random() * 16;
        // 本体
        const body = new THREE.Mesh(
          new THREE.BoxGeometry(2.4, h, 2.4),
          new THREE.MeshBasicMaterial({ color: 0x12122a, fog: false })
        );
        body.position.set(x, -55 + h/2, z);
        scene.add(body);
        // 窓
        const wT = new THREE.Mesh(
          new THREE.PlaneGeometry(2.2, h * 0.92),
          new THREE.MeshBasicMaterial({ color: 0xffe890, fog: false, transparent: true, opacity: 0.85 })
        );
        wT.position.set(x, -55 + h/2, z);
        wT.lookAt(0, wT.position.y, 0);
        wT.translateZ(1.21);
        scene.add(wT);
        // アンテナ
        const ant = new THREE.Mesh(
          new THREE.CylinderGeometry(0.05, 0.1, 4, 6),
          new THREE.MeshBasicMaterial({ color: 0x303040, fog: false })
        );
        ant.position.set(x, -55 + h + 2, z);
        scene.add(ant);
        // 赤い航空灯
        const beacon = new THREE.Mesh(
          new THREE.SphereGeometry(0.18, 8, 6),
          new THREE.MeshBasicMaterial({ color: 0xff2030, fog: false })
        );
        beacon.position.set(x, -55 + h + 4, z);
        beacon.userData.isBeacon = true;
        scene.add(beacon);
      }

      // 🌫 街全体に薄い光のカーペット（光害ヘイズ）
      const hazeTex = (() => {
        const c = document.createElement('canvas'); c.width = 256; c.height = 256;
        const g = c.getContext('2d');
        const grd = g.createRadialGradient(128, 128, 30, 128, 128, 128);
        grd.addColorStop(0, 'rgba(255,200,140,0.35)');
        grd.addColorStop(0.5, 'rgba(200,160,255,0.15)');
        grd.addColorStop(1, 'rgba(80,60,120,0)');
        g.fillStyle = grd; g.fillRect(0, 0, 256, 256);
        return new THREE.CanvasTexture(c);
      })();
      const haze = new THREE.Mesh(
        new THREE.CircleGeometry(180, 32),
        new THREE.MeshBasicMaterial({ map: hazeTex, transparent: true, opacity: 0.6, depthWrite: false, fog: false, blending: THREE.AdditiveBlending })
      );
      haze.rotation.x = -Math.PI / 2;
      haze.position.y = -45;
      scene.add(haze);

      // 🚗 車のヘッドライト（Points で動く軌跡）
      // 同心円状の道路を周回するヘッドライト
      const CARS = 80;
      const carGeo = new THREE.BufferGeometry();
      const carPos = new Float32Array(CARS * 3);
      const carData = []; // {radius, angle, speed, color}
      for (let i = 0; i < CARS; i++) {
        const radius = 40 + Math.floor(i / 10) * 12;
        const angle = (i / CARS) * Math.PI * 2 + Math.random() * 0.3;
        const speed = 0.0015 + Math.random() * 0.0015;
        const dir = i % 2 === 0 ? 1 : -1;
        carData.push({ radius, angle, speed: speed * dir, isHead: i % 2 === 0 });
        carPos[i*3] = Math.cos(angle) * radius;
        carPos[i*3+1] = -54.5;
        carPos[i*3+2] = Math.sin(angle) * radius;
      }
      carGeo.setAttribute('position', new THREE.BufferAttribute(carPos, 3));
      // ヘッドライト用テクスチャ
      const carTex = (() => {
        const c = document.createElement('canvas'); c.width = 64; c.height = 64;
        const g = c.getContext('2d');
        const grd = g.createRadialGradient(32, 32, 0, 32, 32, 32);
        grd.addColorStop(0, 'rgba(255,255,220,1)');
        grd.addColorStop(0.5, 'rgba(255,220,150,0.6)');
        grd.addColorStop(1, 'rgba(255,180,80,0)');
        g.fillStyle = grd; g.fillRect(0, 0, 64, 64);
        return new THREE.CanvasTexture(c);
      })();
      const carMat = new THREE.PointsMaterial({
        map: carTex, color: 0xffffff,
        size: 1.8, sizeAttenuation: true,
        transparent: true, opacity: 0.95,
        blending: THREE.AdditiveBlending,
        depthWrite: false, fog: false,
      });
      const cars = new THREE.Points(carGeo, carMat);
      scene.add(cars);
      // 赤いテールライト（半数を赤に）— vertex colorsで実現
      const carColors = new Float32Array(CARS * 3);
      for (let i = 0; i < CARS; i++) {
        if (carData[i].isHead) {
          carColors[i*3] = 1.0; carColors[i*3+1] = 1.0; carColors[i*3+2] = 0.85;
        } else {
          carColors[i*3] = 1.0; carColors[i*3+1] = 0.2; carColors[i*3+2] = 0.15;
        }
      }
      carGeo.setAttribute('color', new THREE.BufferAttribute(carColors, 3));
      carMat.vertexColors = true;
      // animate 用にデータ保管
      scene.userData.carData = carData;
      scene.userData.cars = cars;

      // 環境光（神殿内は明るく保つ）+ HDRI 環境マップ
      scene.add(new THREE.AmbientLight(0x8070b8, 0.9));
      const hemi = new THREE.HemisphereLight(0xc0a0ff, 0x180830, 0.9);
      scene.add(hemi);
      // 中央からの暖色 fill（本に光を当てる）
      const fillCenter = new THREE.PointLight(0xffe890, 1.2, 30, 1.4);
      fillCenter.position.set(0, 5, 0);
      scene.add(fillCenter);
      // 🎬 HDRI: 神々しい紫の星空
      if (typeof applyCinematicEnv === 'function') {
        applyCinematicEnv(renderer, scene,
          'https://dl.polyhaven.org/file/ph-assets/HDRIs/hdr/1k/dikhololo_night_1k.hdr',
          { intensity: 0.5 });
      }

      // 🏛 ギリシャ神殿風 — 雲の上に浮かぶ白い大理石神殿
      // 大理石テクスチャ（白＋淡い灰の脈）
      const marbleTex = (() => {
        const c = document.createElement('canvas'); c.width = 512; c.height = 512;
        const g = c.getContext('2d');
        const grd = g.createLinearGradient(0, 0, 512, 512);
        grd.addColorStop(0, '#fafaf6'); grd.addColorStop(0.5, '#e8e6e0'); grd.addColorStop(1, '#d8d4cc');
        g.fillStyle = grd; g.fillRect(0, 0, 512, 512);
        // 大理石の脈
        for (let i = 0; i < 30; i++) {
          g.strokeStyle = `rgba(${180+Math.random()*40},${175+Math.random()*40},${165+Math.random()*40},${0.15+Math.random()*0.25})`;
          g.lineWidth = 0.5 + Math.random() * 1.5;
          g.beginPath();
          let x = Math.random()*512, y = Math.random()*512;
          g.moveTo(x, y);
          for (let k = 0; k < 14; k++) {
            x += (Math.random()-0.5)*60; y += (Math.random()-0.5)*60;
            g.lineTo(x, y);
          }
          g.stroke();
        }
        // ブロック目地
        g.strokeStyle = 'rgba(140,135,125,0.3)'; g.lineWidth = 1;
        for (let i = 0; i <= 8; i++) {
          g.beginPath(); g.moveTo(i*64, 0); g.lineTo(i*64, 512); g.stroke();
          g.beginPath(); g.moveTo(0, i*64); g.lineTo(512, i*64); g.stroke();
        }
        const t = new THREE.CanvasTexture(c);
        t.wrapS = t.wrapT = THREE.RepeatWrapping;
        return t;
      })();
      const marbleMat = new THREE.MeshStandardMaterial({
        map: marbleTex, roughness: 0.45, metalness: 0.1,
        color: 0xffffff, envMapIntensity: 1.1,
      });

      // === 神殿のサイズ（矩形プラン）— 広く ===
      const T_W = 26; // 横幅 (旧18)
      const T_D = 36; // 奥行 (旧28)
      const T_H = 10;  // 柱の高さ
      const STEP_H = 0.35;

      // 階段付き基壇（3段）
      for (let s = 0; s < 3; s++) {
        const stepRepeat = marbleTex.clone();
        stepRepeat.wrapS = stepRepeat.wrapT = THREE.RepeatWrapping;
        stepRepeat.repeat.set(T_W * 0.4, T_D * 0.4);
        const w = T_W + 4 - s * 1.2;
        const d = T_D + 4 - s * 1.2;
        const step = new THREE.Mesh(
          new THREE.BoxGeometry(w, STEP_H, d),
          new THREE.MeshStandardMaterial({ map: stepRepeat, roughness: 0.5, metalness: 0.1, color: 0xffffff })
        );
        step.position.y = -1.5 + s * STEP_H;
        scene.add(step);
      }
      // メインの床（神殿の基盤）
      const floorRepeat = marbleTex.clone();
      floorRepeat.wrapS = floorRepeat.wrapT = THREE.RepeatWrapping;
      floorRepeat.repeat.set(T_W * 0.5, T_D * 0.5);
      const floor = new THREE.Mesh(
        new THREE.BoxGeometry(T_W + 2, 0.3, T_D + 2),
        new THREE.MeshStandardMaterial({ map: floorRepeat, roughness: 0.35, metalness: 0.15, color: 0xffffff })
      );
      floor.position.y = -0.45;
      scene.add(floor);

      // === ドリス式柱（縦のフルート溝で表現したテクスチャ） ===
      const colTex = (() => {
        const c = document.createElement('canvas'); c.width = 256; c.height = 512;
        const g = c.getContext('2d');
        // 大理石ベース
        const grd = g.createLinearGradient(0, 0, 256, 0);
        grd.addColorStop(0, '#e8e4dc'); grd.addColorStop(0.5, '#fafaf4'); grd.addColorStop(1, '#e0dcd2');
        g.fillStyle = grd; g.fillRect(0, 0, 256, 512);
        // フルート（縦溝）— 20本
        for (let i = 0; i < 20; i++) {
          const x = i * (256 / 20);
          const grdF = g.createLinearGradient(x, 0, x + 256/20, 0);
          grdF.addColorStop(0, 'rgba(160,156,148,0.4)');
          grdF.addColorStop(0.5, 'rgba(255,255,255,0.0)');
          grdF.addColorStop(1, 'rgba(160,156,148,0.4)');
          g.fillStyle = grdF;
          g.fillRect(x, 0, 256/20, 512);
        }
        // 経年の汚れ
        for (let i = 0; i < 60; i++) {
          g.fillStyle = `rgba(120,110,95,${0.05+Math.random()*0.1})`;
          g.fillRect(Math.random()*256, Math.random()*512, 1+Math.random()*2, 1+Math.random()*4);
        }
        return new THREE.CanvasTexture(c);
      })();
      const fluteMat = new THREE.MeshStandardMaterial({
        map: colTex, roughness: 0.55, metalness: 0.08, color: 0xffffff, envMapIntensity: 1.0,
      });
      // 柱を作る関数（ドリス式: 柱頭+本体+台座）
      function makeColumn(x, z, height) {
        const g = new THREE.Group();
        // 本体（フルート溝のシリンダー）
        const shaft = new THREE.Mesh(
          new THREE.CylinderGeometry(0.5, 0.55, height, 24),
          fluteMat
        );
        shaft.position.y = height / 2;
        g.add(shaft);
        // 柱頭（エキヌス + アバクス）
        const echinus = new THREE.Mesh(
          new THREE.CylinderGeometry(0.7, 0.5, 0.18, 16),
          marbleMat
        );
        echinus.position.y = height + 0.09;
        g.add(echinus);
        const abacus = new THREE.Mesh(
          new THREE.BoxGeometry(1.2, 0.18, 1.2),
          marbleMat
        );
        abacus.position.y = height + 0.27;
        g.add(abacus);
        // 柱の台座（プリンス）
        const pBase = new THREE.Mesh(
          new THREE.CylinderGeometry(0.65, 0.7, 0.15, 16),
          marbleMat
        );
        pBase.position.y = -0.075;
        g.add(pBase);
        g.position.set(x, 0, z);
        return g;
      }
      // 周囲の柱（ペリスタイル）— 矩形配置
      const COL_FRONT = 8;  // 前後 8本ずつ
      const COL_SIDE = 11;  // 側面 11本ずつ（最前最後を含めて）
      // 前面 (入口側 z=+T_D/2)
      for (let i = 0; i < COL_FRONT; i++) {
        const x = -T_W/2 + (T_W / (COL_FRONT - 1)) * i;
        scene.add(makeColumn(x, T_D / 2, T_H));
      }
      // 背面
      for (let i = 0; i < COL_FRONT; i++) {
        const x = -T_W/2 + (T_W / (COL_FRONT - 1)) * i;
        scene.add(makeColumn(x, -T_D / 2, T_H));
      }
      // 左右側面（最前/最後を除く）
      for (let i = 1; i < COL_SIDE - 1; i++) {
        const z = -T_D/2 + (T_D / (COL_SIDE - 1)) * i;
        scene.add(makeColumn(-T_W/2, z, T_H));
        scene.add(makeColumn( T_W/2, z, T_H));
      }

      // === エンタブラチュア（柱の上の梁）===
      // フリーズ（横一周の太い梁）
      const friezeMat = marbleMat;
      const friezeFront = new THREE.Mesh(
        new THREE.BoxGeometry(T_W + 1.4, 0.7, 0.7),
        friezeMat
      );
      friezeFront.position.set(0, T_H + 0.55, T_D / 2);
      scene.add(friezeFront);
      const friezeBack = friezeFront.clone();
      friezeBack.position.z = -T_D / 2;
      scene.add(friezeBack);
      const friezeLeft = new THREE.Mesh(
        new THREE.BoxGeometry(0.7, 0.7, T_D + 1.4),
        friezeMat
      );
      friezeLeft.position.set(-T_W / 2, T_H + 0.55, 0);
      scene.add(friezeLeft);
      const friezeRight = friezeLeft.clone();
      friezeRight.position.x = T_W / 2;
      scene.add(friezeRight);
      // コーニス（フリーズの下の薄い帯）
      const corniceFront = new THREE.Mesh(
        new THREE.BoxGeometry(T_W + 2, 0.18, 0.85),
        new THREE.MeshStandardMaterial({ color: 0xf0eee4, roughness: 0.4, metalness: 0.15 })
      );
      corniceFront.position.set(0, T_H + 1.0, T_D / 2);
      scene.add(corniceFront);
      const corniceBack = corniceFront.clone();
      corniceBack.position.z = -T_D / 2;
      scene.add(corniceBack);

      // === 三角破風（ペディメント） — 前面と背面 ===
      function makePediment(side) {
        // 三角形の正面
        const shape = new THREE.Shape();
        const half = T_W / 2 + 1;
        const peakH = 2.6;
        shape.moveTo(-half, 0);
        shape.lineTo(half, 0);
        shape.lineTo(0, peakH);
        shape.lineTo(-half, 0);
        const pedGeo = new THREE.ExtrudeGeometry(shape, { depth: 0.4, bevelEnabled: false });
        const ped = new THREE.Mesh(pedGeo, new THREE.MeshStandardMaterial({
          color: 0xf8f6f0, roughness: 0.5, metalness: 0.1, side: THREE.DoubleSide,
        }));
        ped.position.set(0, T_H + 1.18, side * (T_D / 2 + 0.2));
        scene.add(ped);
      }
      makePediment(1);
      makePediment(-1);

      // === 屋根（傾斜した2枚の平面、瓦感） ===
      const roofMat = new THREE.MeshStandardMaterial({
        color: 0xc8c0b0, roughness: 0.7, metalness: 0.05, side: THREE.DoubleSide,
      });
      // 屋根の傾斜板（前面側 / 背面側）
      const roofW = Math.hypot(T_W / 2 + 1, 2.6);
      // 前面の傾斜
      const roofFront = new THREE.Mesh(
        new THREE.PlaneGeometry(T_W + 2.2, T_D + 2.2),
        roofMat
      );
      // 屋根を山形に分割せず、簡易に1枚で薄く（神殿として印象的）
      // 代わりに2枚の傾斜板で山形を形成
      const half_T_W = T_W / 2 + 1.1;
      const peakH = 2.6;
      const slope = Math.atan2(peakH, half_T_W);
      const slopeLen = Math.hypot(half_T_W, peakH);
      const roofL = new THREE.Mesh(new THREE.PlaneGeometry(slopeLen * 2, T_D + 2.2), roofMat);
      roofL.position.set(-half_T_W / 2, T_H + 1.18 + peakH / 2, 0);
      roofL.rotation.z = slope;
      roofL.rotation.y = Math.PI / 2;
      scene.add(roofL);
      const roofR = roofL.clone();
      roofR.position.set(half_T_W / 2, T_H + 1.18 + peakH / 2, 0);
      roofR.rotation.z = -slope;
      roofR.rotation.y = Math.PI / 2;
      scene.add(roofR);

      // === 🔥 灯火（DQ7風の燭台）— 廊下の左右に並べる ===
      const torchFlames = []; // animate で揺らす
      function makeTorch(x, z) {
        const g = new THREE.Group();
        // 石の柱（燭台の脚）
        const stand = new THREE.Mesh(
          new THREE.CylinderGeometry(0.18, 0.25, 2.5, 12),
          new THREE.MeshStandardMaterial({ color: 0x7a7068, roughness: 0.85 })
        );
        stand.position.y = 1.25;
        g.add(stand);
        // 受け皿（金属）
        const dish = new THREE.Mesh(
          new THREE.CylinderGeometry(0.32, 0.22, 0.18, 14),
          new THREE.MeshStandardMaterial({ color: 0x4a3a20, roughness: 0.5, metalness: 0.7 })
        );
        dish.position.y = 2.6;
        g.add(dish);
        // 炎の核（明るいオレンジ）
        const flame = new THREE.Mesh(
          new THREE.SphereGeometry(0.22, 12, 10),
          new THREE.MeshBasicMaterial({ color: 0xffe8a0 })
        );
        flame.position.y = 2.95;
        flame.scale.set(0.7, 1.4, 0.7);
        g.add(flame);
        // 外炎（オレンジの後光）
        const haloC = (() => {
          const c = document.createElement('canvas'); c.width = 128; c.height = 128;
          const cg = c.getContext('2d');
          const grd = cg.createRadialGradient(64, 64, 0, 64, 64, 64);
          grd.addColorStop(0, 'rgba(255,180,80,1)');
          grd.addColorStop(0.4, 'rgba(255,140,40,0.6)');
          grd.addColorStop(1, 'rgba(255,80,20,0)');
          cg.fillStyle = grd; cg.fillRect(0, 0, 128, 128);
          return new THREE.CanvasTexture(c);
        })();
        const halo = new THREE.Sprite(new THREE.SpriteMaterial({
          map: haloC, transparent: true, opacity: 0.7,
          depthWrite: false, blending: THREE.AdditiveBlending,
        }));
        halo.scale.set(1.4, 1.4, 1);
        halo.position.y = 3.0;
        g.add(halo);
        // 光源（暖色 PointLight）
        const fLight = new THREE.PointLight(0xff9050, 1.6, 8, 1.6);
        fLight.position.y = 2.9;
        g.add(fLight);
        g.position.set(x, 0, z);
        scene.add(g);
        torchFlames.push({ flame, halo, light: fLight, baseScale: 1.4, basePower: 1.6 });
      }
      // 灯火の配置: 廊下に沿って 左右 4対（z=+8, +2, -4, -10）
      const torchZs = [8, 2, -4, -10];
      torchZs.forEach(z => {
        makeTorch(-T_W/2 + 1.0, z);  // 左
        makeTorch(T_W/2 - 1.0, z);   // 右
      });
      scene.userData.torchFlames = torchFlames;

      // === 階段（前面のみ大きく）===
      for (let s = 0; s < 5; s++) {
        const step = new THREE.Mesh(
          new THREE.BoxGeometry(T_W * 0.6 + s * 0.4, STEP_H, 0.6),
          marbleMat
        );
        step.position.set(0, -1.5 + s * STEP_H * 0.7, T_D / 2 + 1.2 + s * 0.6);
        scene.add(step);
      }

      // === 内部のフィル光 ===
      const centerLight = new THREE.PointLight(0xfff0e0, 2.8, 40, 1.4);
      centerLight.position.set(0, T_H - 1, 0);
      scene.add(centerLight);
      // 入口側の温かい光
      const entryLight = new THREE.PointLight(0xffd890, 2.5, 25, 1.5);
      entryLight.position.set(0, 4, T_D / 2 - 2);
      scene.add(entryLight);
      // 主神側の神聖な光
      const altarLight = new THREE.PointLight(0xc0d8ff, 2.0, 20, 1.5);
      altarLight.position.set(0, 5, -T_D / 2 + 3);
      scene.add(altarLight);

      // === シアンに光る側面の聖なる窓（参考画像の青い水晶のような） ===
      for (let i = 0; i < 4; i++) {
        const z = -T_D/2 + 4 + i * (T_D - 8) / 3;
        for (const sx of [-1, 1]) {
          const win = new THREE.Mesh(
            new THREE.BoxGeometry(0.3, 1.6, 1.0),
            new THREE.MeshStandardMaterial({
              color: 0x40d8e0, transparent: true, opacity: 0.7,
              emissive: 0x40d8e0, emissiveIntensity: 1.2,
              roughness: 0.2, metalness: 0.3,
            })
          );
          win.position.set(sx * (T_W / 2), 4, z);
          scene.add(win);
          // 周囲の枠
          const frame = new THREE.Mesh(
            new THREE.BoxGeometry(0.4, 1.9, 1.3),
            new THREE.MeshStandardMaterial({ color: 0xe0dcd0, roughness: 0.5 })
          );
          frame.position.set(sx * (T_W / 2 + 0.05), 4, z);
          scene.add(frame);
        }
      }

      // 🚪 旧入口アーチ — ギリシャ神殿の正面が入口の役目を果たすため無効化
      if (false) {
      const zoneArch = new THREE.Group();
      const archStone = new THREE.MeshStandardMaterial({ color: 0xc8b8d8, roughness: 0.6, metalness: 0.15 });
      const archGold = new THREE.MeshStandardMaterial({ color: 0xe8c060, roughness: 0.4, metalness: 0.85, emissive: 0x4a3008, emissiveIntensity: 0.4 });
      // 左右の柱
      for (const dx of [-2.4, 2.4]) {
        const col = new THREE.Mesh(new THREE.CylinderGeometry(0.5, 0.6, 7.5, 16), archStone);
        col.position.set(dx, 3.75, 0);
        zoneArch.add(col);
        const cap = new THREE.Mesh(new THREE.CylinderGeometry(0.7, 0.7, 0.3, 16), archGold);
        cap.position.set(dx, 7.5, 0); zoneArch.add(cap);
        const base = new THREE.Mesh(new THREE.CylinderGeometry(0.78, 0.78, 0.3, 16), archGold);
        base.position.set(dx, 0.15, 0); zoneArch.add(base);
      }
      // 半円アーチ（金）
      const archMesh = new THREE.Mesh(
        new THREE.TorusGeometry(2.4, 0.28, 8, 24, Math.PI),
        archGold
      );
      archMesh.position.set(0, 7.5, 0);
      zoneArch.add(archMesh);
      // キーストーン（神話シンボル）
      const ks = new THREE.Mesh(new THREE.BoxGeometry(0.7, 0.7, 0.55), archGold);
      ks.position.set(0, 9.95, 0); zoneArch.add(ks);
      // 神話名プレート（裏に）
      const plateC = document.createElement('canvas'); plateC.width = 1024; plateC.height = 256;
      const pg = plateC.getContext('2d');
      const grd = pg.createLinearGradient(0, 0, 0, 256);
      grd.addColorStop(0, 'rgba(20,10,30,0.95)'); grd.addColorStop(1, 'rgba(40,28,60,0.95)');
      pg.fillStyle = grd; pg.fillRect(0, 0, 1024, 256);
      pg.strokeStyle = '#e8c060'; pg.lineWidth = 5;
      pg.strokeRect(8, 8, 1008, 240);
      pg.font = 'bold 110px "Shippori Mincho", serif';
      pg.fillStyle = '#fff8e0';
      pg.shadowColor = '#e8c060'; pg.shadowBlur = 22;
      pg.textAlign = 'center'; pg.textBaseline = 'middle';
      pg.fillText(PANTHEON_DATA[zone]?.name || '神 殿', 512, 110);
      pg.shadowBlur = 0;
      pg.font = 'italic 28px "Cormorant Garamond", serif';
      pg.fillStyle = '#e8c060';
      pg.fillText(`— ${PANTHEON_DATA[zone]?.gods?.length || ''} Deities —`, 512, 200);
      const plateTex = new THREE.CanvasTexture(plateC);
      if ('colorSpace' in plateTex) plateTex.colorSpace = THREE.SRGBColorSpace;
      const plate = new THREE.Mesh(
        new THREE.PlaneGeometry(6, 1.5),
        new THREE.MeshBasicMaterial({ map: plateTex, transparent: true, side: THREE.DoubleSide })
      );
      plate.position.set(0, 11.0, 0);
      zoneArch.add(plate);
      // 階段
      for (let s = 0; s < 4; s++) {
        const step = new THREE.Mesh(
          new THREE.BoxGeometry(7 + s*0.5, 0.18, 0.5),
          archStone
        );
        step.position.set(0, -s * 0.18, 0.6 + s * 0.5);
        zoneArch.add(step);
      }
      // 入口の光
      const archLight = new THREE.PointLight(0xffd890, 2.0, 14, 1.4);
      archLight.position.set(0, 4, -1);
      zoneArch.add(archLight);
      zoneArch.position.set(0, 0, 15);
      scene.add(zoneArch);
      } // 🏛 旧入口アーチ無効化終了

      // 🏛 大入口：南方向（z=+22 方向）に荘厳な門
      if (zone === 'hub') {
        const portalG = new THREE.Group();
        const stoneMat = new THREE.MeshStandardMaterial({ color: 0xc8b8d8, roughness: 0.6, metalness: 0.15 });
        const goldMat = new THREE.MeshStandardMaterial({ color: 0xe8c060, roughness: 0.4, metalness: 0.85, emissive: 0x4a3008, emissiveIntensity: 0.35 });
        // 門柱（左右）
        for (const dx of [-2.4, 2.4]) {
          const col = new THREE.Mesh(new THREE.CylinderGeometry(0.55, 0.65, 8.5, 18), stoneMat);
          col.position.set(dx, 4.25, 0);
          portalG.add(col);
          // 柱頭装飾（金の輪）
          const cap = new THREE.Mesh(new THREE.CylinderGeometry(0.75, 0.75, 0.35, 18), goldMat);
          cap.position.set(dx, 8.2, 0);
          portalG.add(cap);
          const base = new THREE.Mesh(new THREE.CylinderGeometry(0.85, 0.85, 0.35, 18), goldMat);
          base.position.set(dx, 0.18, 0);
          portalG.add(base);
        }
        // 半円アーチ（金）
        const archGeo = new THREE.TorusGeometry(2.4, 0.32, 10, 28, Math.PI);
        const arch = new THREE.Mesh(archGeo, goldMat);
        arch.position.set(0, 8.2, 0);
        portalG.add(arch);
        // キーストーン
        const key = new THREE.Mesh(new THREE.BoxGeometry(0.7, 0.7, 0.6), goldMat);
        key.position.set(0, 10.65, 0);
        portalG.add(key);
        // 門の上に「神 殿」プレート
        const plateC = document.createElement('canvas'); plateC.width = 1024; plateC.height = 256;
        const pg2 = plateC.getContext('2d');
        const grd = pg2.createLinearGradient(0, 0, 0, 256);
        grd.addColorStop(0, 'rgba(20,10,30,0.95)'); grd.addColorStop(1, 'rgba(40,28,60,0.95)');
        pg2.fillStyle = grd; pg2.fillRect(0, 0, 1024, 256);
        pg2.strokeStyle = '#e8c060'; pg2.lineWidth = 5;
        pg2.strokeRect(8, 8, 1008, 240);
        pg2.lineWidth = 1.5;
        pg2.strokeRect(20, 20, 984, 216);
        // 装飾紋章（左右）
        ['❦','❦'].forEach((g, i) => {
          pg2.font = '60px serif';
          pg2.fillStyle = '#e8c060';
          pg2.textAlign = 'center'; pg2.textBaseline = 'middle';
          pg2.fillText(g, i === 0 ? 100 : 924, 128);
        });
        // 「神 殿」
        pg2.font = 'bold 140px "Shippori Mincho", serif';
        pg2.fillStyle = '#fff8e0';
        pg2.shadowColor = '#e8c060'; pg2.shadowBlur = 24;
        pg2.fillText('神　殿', 512, 110);
        pg2.shadowBlur = 0;
        pg2.font = 'italic 30px "Cormorant Garamond", serif';
        pg2.fillStyle = '#e8c060';
        pg2.fillText('—  Pantheon  of  the  Six  Mythologies  —', 512, 200);
        const plateTex = new THREE.CanvasTexture(plateC);
        if ('colorSpace' in plateTex) plateTex.colorSpace = THREE.SRGBColorSpace;
        const plate = new THREE.Mesh(
          new THREE.PlaneGeometry(6.5, 1.6),
          new THREE.MeshBasicMaterial({ map: plateTex, transparent: true, side: THREE.DoubleSide })
        );
        plate.position.set(0, 11.7, 0);
        portalG.add(plate);
        // 階段（外向き＝門の外側）
        for (let s = 0; s < 5; s++) {
          const step = new THREE.Mesh(
            new THREE.BoxGeometry(8 + s*0.6, 0.18, 0.6),
            stoneMat
          );
          step.position.set(0, -s * 0.18, 1.0 + s * 0.6);
          portalG.add(step);
        }
        // 入口の光（門内側へ柔らかい光）
        const entLight = new THREE.PointLight(0xffd890, 2.5, 18, 1.4);
        entLight.position.set(0, 4, -0.5);
        portalG.add(entLight);
        // 🌫 門の外に「入口の靄」
        const mistC = document.createElement('canvas'); mistC.width = 256; mistC.height = 256;
        const mg = mistC.getContext('2d');
        const mgr = mg.createRadialGradient(128, 128, 0, 128, 128, 128);
        mgr.addColorStop(0, 'rgba(255,232,200,0.7)');
        mgr.addColorStop(1, 'rgba(255,232,200,0)');
        mg.fillStyle = mgr; mg.fillRect(0, 0, 256, 256);
        const mistTex = new THREE.CanvasTexture(mistC);
        const mist = new THREE.Sprite(new THREE.SpriteMaterial({
          map: mistTex, transparent: true, opacity: 0.5, depthWrite: false,
        }));
        mist.scale.set(7, 5, 1);
        mist.position.set(0, 4, 1);
        portalG.add(mist);
        // 門の位置
        portalG.position.set(0, 0, 22);
        portalG.rotation.y = Math.PI; // 門を中心方向に向ける
        scene.add(portalG);

        // ⛩ 浮かぶ神殿らしさを強調 — 神殿の縁に金の縁取りを
        const rim = new THREE.Mesh(
          new THREE.TorusGeometry(20, 0.18, 8, 64),
          new THREE.MeshStandardMaterial({ color: 0xe8c060, roughness: 0.4, metalness: 0.85, emissive: 0x4a3008, emissiveIntensity: 0.4 })
        );
        rim.rotation.x = Math.PI / 2;
        rim.position.y = 0.05;
        scene.add(rim);
        // 床下に神殿の基壇（円形プラットフォーム）が浮いている感じ
        const basePlat = new THREE.Mesh(
          new THREE.CylinderGeometry(22, 24, 1.8, 48),
          new THREE.MeshStandardMaterial({ color: 0x5a4a78, roughness: 0.6, metalness: 0.25 })
        );
        basePlat.position.y = -1.0;
        scene.add(basePlat);
        // 基壇の下にも金縁
        const baseRim = new THREE.Mesh(
          new THREE.TorusGeometry(24, 0.22, 8, 64),
          new THREE.MeshStandardMaterial({ color: 0xe8c060, roughness: 0.4, metalness: 0.85, emissive: 0x4a3008, emissiveIntensity: 0.5 })
        );
        baseRim.rotation.x = Math.PI / 2;
        baseRim.position.y = -1.95;
        scene.add(baseRim);
      }
      } // ← end of if (zone !== 'hub') — テンプル構造はHUB以外のみ

      // 🌌 HUB は魂の宇宙: 大量の追加星と銀河
      if (zone === 'hub') {
        // より深い星空（宇宙感を強化）
        const deepGeo = new THREE.BufferGeometry();
        const DEEP = 1200;
        const dp = new Float32Array(DEEP * 3);
        const dc = new Float32Array(DEEP * 3);
        for (let i = 0; i < DEEP; i++) {
          const r = 30 + Math.random() * 50;
          const th = Math.random() * Math.PI * 2;
          const ph = Math.acos(2 * Math.random() - 1);
          dp[i*3]   = Math.sin(ph) * Math.cos(th) * r;
          dp[i*3+1] = Math.cos(ph) * r;
          dp[i*3+2] = Math.sin(ph) * Math.sin(th) * r;
          // 色: 白〜淡い紫〜淡い金
          const tone = Math.random();
          if (tone < 0.5) { dc[i*3]=1; dc[i*3+1]=1; dc[i*3+2]=1; }
          else if (tone < 0.8) { dc[i*3]=0.8; dc[i*3+1]=0.7; dc[i*3+2]=1; }
          else { dc[i*3]=1; dc[i*3+1]=0.9; dc[i*3+2]=0.6; }
        }
        deepGeo.setAttribute('position', new THREE.BufferAttribute(dp, 3));
        deepGeo.setAttribute('color', new THREE.BufferAttribute(dc, 3));
        scene.add(new THREE.Points(deepGeo, new THREE.PointsMaterial({
          size: 0.5, sizeAttenuation: true, vertexColors: true,
          transparent: true, opacity: 0.95, depthWrite: false, fog: false,
        })));
        // 紫の星雲
        for (let i = 0; i < 3; i++) {
          const nc = document.createElement('canvas'); nc.width = 256; nc.height = 256;
          const ng = nc.getContext('2d');
          const grd = ng.createRadialGradient(128, 128, 0, 128, 128, 128);
          const cols = [['#a060d0','#3010a0'], ['#d04060','#4a1830'], ['#4080d0','#0a2050']][i];
          grd.addColorStop(0, cols[0] + 'cc');
          grd.addColorStop(1, cols[1] + '00');
          ng.fillStyle = grd; ng.fillRect(0, 0, 256, 256);
          const tex = new THREE.CanvasTexture(nc);
          const sp2 = new THREE.Sprite(new THREE.SpriteMaterial({ map: tex, transparent: true, opacity: 0.5, depthWrite: false }));
          sp2.scale.set(40, 40, 1);
          const a = (i / 3) * Math.PI * 2;
          sp2.position.set(Math.cos(a) * 35, (Math.random()-0.5)*15, Math.sin(a) * 35);
          scene.add(sp2);
        }
        // 環境光（魂が光る程度に弱く）
        scene.add(new THREE.AmbientLight(0x6080a0, 0.5));
        scene.add(new THREE.HemisphereLight(0x88aacc, 0x110820, 0.6));
        // 🎬 HDRI（夜の宇宙）
        if (typeof applyCinematicEnv === 'function') {
          applyCinematicEnv(renderer, scene,
            'https://dl.polyhaven.org/file/ph-assets/HDRIs/hdr/1k/satara_night_1k.hdr',
            { intensity: 0.4 });
        }
        scene.background = new THREE.Color(0x02010a);
        scene.fog = new THREE.FogExp2(0x02010a, 0.012);
      }

      // 配置するアイテム
      const items = (zone === 'hub')
        ? Object.entries(PANTHEON_DATA).map(([key, d]) => ({
            type: 'pantheon', key, name: d.name, emoji: d.emoji, accent: d.accent,
            sub: d.gods.length + '柱の神'
          }))
        : (PANTHEON_DATA[zone]?.gods || []).map(g => ({
            type: 'god', name: g.n, sub: g.t, img: g.img, lore: g.lore,
            accent: PANTHEON_DATA[zone].accent,
          }));

      // 配置：HUB=浮かぶ神話の本（円形）、ゾーン内=DQ7風の神殿廊下
      const N = items.length;
      const ringR = 12;
      const isHubZone = (zone === 'hub');

      // ⛩ ゾーン内は「廊下＋奥の主神」レイアウト
      // 入口 z=14 → 中央 z=0 → 主神 z=-9
      function zoneLayout(idx, total) {
        // 主神を最後の1柱に。残りは2列で参道に並べる。
        const others = total - 1;
        if (idx === total - 1) {
          // 主神（中央奥）— 大きめスケール
          return { x: 0, z: -9, scale: 1.35, isMain: true };
        }
        // 残りを左右に分割
        const half = Math.ceil(others / 2);
        const isLeft = idx < half;
        const rowIndex = isLeft ? idx : (idx - half);
        const rowCount = isLeft ? half : (others - half);
        // 廊下に沿って z = 4 → -6 で並ぶ（入口側 z>4 は石板用に空ける）
        const t = rowCount > 1 ? rowIndex / (rowCount - 1) : 0;
        const z = 4 - t * 10; // 4, -1, -6 ...
        const x = isLeft ? -4.5 : 4.5;
        return { x, z, scale: 1.0, isMain: false };
      }

      items.forEach((item, i) => {
        let px, pz, hubY = 0, scale = 1, isMain = false;
        if (isHubZone) {
          const a = (i / N) * Math.PI * 2;
          px = Math.cos(a) * ringR;
          pz = Math.sin(a) * ringR;
          hubY = 1.8 + Math.sin(i * 1.7) * 1.0;
        } else {
          const L = zoneLayout(i, N);
          px = L.x; pz = L.z; scale = L.scale; isMain = L.isMain;
        }
        const group = new THREE.Group();
        group.position.set(px, hubY, pz);
        if (!isHubZone) group.scale.setScalar(scale);
        group.userData.isMain = isMain;

        if (isHubZone) {
          // 📖 HUB: 浮かぶ豪華な神話本
          const accentHex = '#' + (item.accent || 0x9080d0).toString(16).padStart(6, '0');
          const c = document.createElement('canvas'); c.width = 512; c.height = 720;
          const cg = c.getContext('2d');
          // 神話別カラーマップ
          const palette = {
            genesis: ['#3a2818','#0a0408'],
            greek:   ['#1a2a4a','#050818'],
            japan:   ['#3a1a1a','#0a0408'],
            norse:   ['#2a3a48','#080a14'],
            egypt:   ['#6a4a1a','#1a1004'],
            hindu:   ['#3a1830','#100418'],
          };
          const cols = palette[item.key] || ['#2a1840','#0a0418'];
          const grd = cg.createRadialGradient(256, 360, 50, 256, 360, 600);
          grd.addColorStop(0, cols[0]); grd.addColorStop(1, cols[1]);
          cg.fillStyle = grd; cg.fillRect(0, 0, 512, 720);
          // 質感ノイズ
          for (let n = 0; n < 1500; n++) {
            cg.fillStyle = `rgba(255,255,255,${0.03+Math.random()*0.07})`;
            cg.fillRect(Math.random()*512, Math.random()*720, 1.2, 1.2);
          }
          // 二重装飾枠
          cg.strokeStyle = accentHex; cg.lineWidth = 8;
          cg.strokeRect(20, 20, 472, 680);
          cg.lineWidth = 2;
          cg.strokeRect(36, 36, 440, 648);
          // 角飾り
          [[36,36],[476,36],[36,684],[476,684]].forEach(([cx,cy])=>{
            cg.fillStyle = accentHex;
            cg.beginPath(); cg.arc(cx,cy,7,0,Math.PI*2); cg.fill();
          });
          // 神話名（神話によって縦書き/横書き判断、ここは折り返し）
          cg.font = 'bold 52px "Shippori Mincho", serif';
          cg.fillStyle = accentHex;
          cg.textAlign = 'center'; cg.textBaseline = 'middle';
          cg.shadowColor = 'rgba(0,0,0,0.7)'; cg.shadowBlur = 12;
          const titleLines = (item.name || '').match(/.{1,6}/g) || [item.name];
          titleLines.forEach((l, li) => cg.fillText(l, 256, 150 + li * 60));
          cg.shadowBlur = 0;
          // セパレーター
          cg.strokeStyle = accentHex; cg.lineWidth = 1.5;
          cg.beginPath(); cg.moveTo(160, 290); cg.lineTo(352, 290); cg.stroke();
          cg.fillStyle = accentHex; cg.beginPath(); cg.arc(256, 290, 5, 0, Math.PI*2); cg.fill();
          // シンボル/絵文字
          cg.font = '210px serif';
          cg.fillStyle = accentHex;
          cg.shadowColor = 'rgba(0,0,0,0.6)'; cg.shadowBlur = 22;
          cg.fillText(item.emoji || '✦', 256, 460);
          cg.shadowBlur = 0;
          // 下部装飾
          cg.strokeStyle = accentHex; cg.lineWidth = 1;
          cg.beginPath(); cg.moveTo(120, 580); cg.lineTo(392, 580); cg.stroke();
          // 副題
          cg.font = 'italic 22px "Cormorant Garamond", "Shippori Mincho", serif';
          cg.fillStyle = '#fff8e0';
          cg.fillText(item.sub || '', 256, 620);
          cg.font = '16px "Cormorant Garamond", serif';
          cg.fillStyle = accentHex;
          cg.fillText('— Mythologia —', 256, 660);
          cg.font = '24px serif';
          cg.fillText('❦', 256, 690);
          const coverTex = new THREE.CanvasTexture(c);
          if ('colorSpace' in coverTex) coverTex.colorSpace = THREE.SRGBColorSpace;
          // 重厚な本体
          const bookMesh = new THREE.Mesh(
            new THREE.BoxGeometry(2.6, 3.8, 0.55),
            [
              new THREE.MeshStandardMaterial({ color: 0x2a1810, roughness: 0.7 }),
              new THREE.MeshStandardMaterial({ color: 0x2a1810, roughness: 0.7 }),
              new THREE.MeshStandardMaterial({ color: 0xf5e8c0, roughness: 0.85 }),
              new THREE.MeshStandardMaterial({ color: 0xf5e8c0, roughness: 0.85 }),
              new THREE.MeshStandardMaterial({ map: coverTex, roughness: 0.55, metalness: 0.15 }),
              new THREE.MeshStandardMaterial({ color: 0x2a1810, roughness: 0.7 }),
            ]
          );
          group.add(bookMesh);
          // 表紙が中央(0,0)を向くように初期回転 — animate ループで微調整される
          bookMesh.rotation.y = Math.atan2(-px, -pz);
          // 後光（accent色）
          const haloC = document.createElement('canvas'); haloC.width = 256; haloC.height = 256;
          const hc = haloC.getContext('2d');
          const hg = hc.createRadialGradient(128, 128, 0, 128, 128, 128);
          hg.addColorStop(0, accentHex + 'cc');
          hg.addColorStop(0.5, accentHex + '44');
          hg.addColorStop(1, accentHex + '00');
          hc.fillStyle = hg; hc.fillRect(0, 0, 256, 256);
          const halo = new THREE.Sprite(new THREE.SpriteMaterial({
            map: new THREE.CanvasTexture(haloC), color: 0xffffff,
            transparent: true, opacity: 0.55, depthWrite: false, blending: THREE.AdditiveBlending,
          }));
          halo.scale.set(7, 7, 1);
          group.add(halo);
          group.userData = { item, isBook: true, bookMesh, halo, baseY: group.position.y };
          plinths.push(group);
          scene.add(group);
          return; // HUB はここで終了（古い plinth UI は使わない）
        }

        // 以下、ゾーン内の神様用台座（HUB 以外）
        // 主神（isMain）には特別な装飾を追加
        if (isMain) {
          // 主神の周りに光の柱
          const beamC = document.createElement('canvas'); beamC.width = 64; beamC.height = 256;
          const bg = beamC.getContext('2d');
          const accentHex = '#' + (item.accent || 0xffd890).toString(16).padStart(6, '0');
          const bgrd = bg.createLinearGradient(0, 0, 0, 256);
          bgrd.addColorStop(0, accentHex + '00');
          bgrd.addColorStop(0.5, accentHex + 'aa');
          bgrd.addColorStop(1, accentHex + '00');
          bg.fillStyle = bgrd; bg.fillRect(0, 0, 64, 256);
          const beamTex = new THREE.CanvasTexture(beamC);
          const beam = new THREE.Sprite(new THREE.SpriteMaterial({
            map: beamTex, transparent: true, opacity: 0.55,
            depthWrite: false, blending: THREE.AdditiveBlending,
          }));
          beam.scale.set(4, 9, 1);
          beam.position.y = 4.5;
          group.add(beam);
          // 主神の地面に魔法陣
          const circleC = document.createElement('canvas'); circleC.width = 256; circleC.height = 256;
          const ccg = circleC.getContext('2d');
          ccg.strokeStyle = accentHex; ccg.lineWidth = 3;
          ccg.beginPath(); ccg.arc(128, 128, 110, 0, Math.PI*2); ccg.stroke();
          ccg.lineWidth = 1.5;
          ccg.beginPath(); ccg.arc(128, 128, 90, 0, Math.PI*2); ccg.stroke();
          // 五芒星
          for (let i = 0; i < 5; i++) {
            const a1 = (i / 5) * Math.PI * 2 - Math.PI / 2;
            const a2 = ((i + 2) / 5) * Math.PI * 2 - Math.PI / 2;
            ccg.beginPath();
            ccg.moveTo(128 + Math.cos(a1) * 90, 128 + Math.sin(a1) * 90);
            ccg.lineTo(128 + Math.cos(a2) * 90, 128 + Math.sin(a2) * 90);
            ccg.stroke();
          }
          ccg.fillStyle = accentHex;
          ccg.font = '32px serif'; ccg.textAlign = 'center'; ccg.textBaseline = 'middle';
          ccg.fillText('❋', 128, 128);
          const circleTex = new THREE.CanvasTexture(circleC);
          const magicCircle = new THREE.Mesh(
            new THREE.PlaneGeometry(4.5, 4.5),
            new THREE.MeshBasicMaterial({ map: circleTex, transparent: true, depthWrite: false, blending: THREE.AdditiveBlending })
          );
          magicCircle.rotation.x = -Math.PI / 2;
          magicCircle.position.y = 0.05;
          group.add(magicCircle);
          group.userData.magicCircle = magicCircle;
          // 主神の自己発光
          const mainLight = new THREE.PointLight(item.accent, 2.0, 12, 1.5);
          mainLight.position.y = 3;
          group.add(mainLight);
        }
        const plinth = new THREE.Mesh(
          new THREE.CylinderGeometry(1.2, 1.4, 1.0, 24),
          new THREE.MeshStandardMaterial({ color: 0x2a2040, roughness: 0.5, metalness: 0.4 })
        );
        plinth.position.y = 0.5;
        group.add(plinth);
        // ホログラム円柱（半透明エメッシブ）
        const holoMat = new THREE.MeshBasicMaterial({
          color: item.accent, transparent: true, opacity: 0.18,
          side: THREE.DoubleSide, depthWrite: false,
        });
        const holo = new THREE.Mesh(
          new THREE.CylinderGeometry(0.95, 0.95, 2.4, 16, 1, true),
          holoMat
        );
        holo.position.y = 2.2;
        group.add(holo);
        // ホログラム底のリング
        const ring = new THREE.Mesh(
          new THREE.RingGeometry(0.95, 1.15, 32),
          new THREE.MeshBasicMaterial({ color: item.accent, transparent: true, opacity: 0.6, side: THREE.DoubleSide })
        );
        ring.rotation.x = -Math.PI / 2;
        ring.position.y = 1.05;
        group.add(ring);
        // 中の絵（最初はプレースホルダ）
        const phCanvas = document.createElement('canvas');
        phCanvas.width = 256; phCanvas.height = 384;
        const pg = phCanvas.getContext('2d');
        const grd = pg.createLinearGradient(0, 0, 0, 384);
        grd.addColorStop(0, '#3a2050'); grd.addColorStop(1, '#181028');
        pg.fillStyle = grd; pg.fillRect(0, 0, 256, 384);
        pg.font = 'bold 80px serif'; pg.fillStyle = '#fff';
        pg.textAlign = 'center';
        pg.fillText(item.emoji || '✦', 128, 220);
        pg.font = 'bold 24px serif';
        pg.fillText(item.name.slice(0, 6), 128, 280);
        const phTex = new THREE.CanvasTexture(phCanvas);
        const figMat = new THREE.MeshBasicMaterial({
          map: phTex, transparent: true, depthWrite: false, side: THREE.DoubleSide,
        });
        const figure = new THREE.Mesh(new THREE.PlaneGeometry(1.8, 2.25), figMat);
        figure.position.y = 2.2;
        group.add(figure);
        // まず procedural canvas（フォールバック）を仕込んでおく
        const cv = document.createElement('canvas');
        cv.width = 384; cv.height = 480;
        const ctx = cv.getContext('2d');
        const animTex = new THREE.CanvasTexture(cv);
        if ('colorSpace' in animTex) animTex.colorSpace = THREE.SRGBColorSpace;
        figMat.map = animTex;
        figMat.needsUpdate = true;
        const accentHex = '#' + item.accent.toString(16).padStart(6, '0');
        const animEntry = { ctx, tex: animTex, item, accent: accentHex };
        animatedTextures.push(animEntry);
        // 画像があるなら試みてロード成功したら写真ホログラム化
        if (item.img) {
          loadGodImage(item.img).then(tex => {
            // ホログラム化：写真を accent 色で軽くシアン染め＋発光
            const c2 = document.createElement('canvas');
            const iw = tex.image.width, ih = tex.image.height;
            const tgt = 384, tgtH = Math.round(tgt * (ih / iw));
            c2.width = tgt; c2.height = Math.min(tgtH, 480);
            const cx2 = c2.getContext('2d');
            // 暗背景（ホログラム）
            cx2.fillStyle = '#08051a'; cx2.fillRect(0, 0, c2.width, c2.height);
            // 写真を中央フィット
            const drawH = c2.height;
            const drawW = drawH * (iw / ih);
            cx2.drawImage(tex.image, (c2.width - drawW) / 2, 0, drawW, drawH);
            // accent 色のオーバーレイ（ホログラムグロー）
            cx2.globalCompositeOperation = 'overlay';
            cx2.fillStyle = accentHex; cx2.globalAlpha = 0.22;
            cx2.fillRect(0, 0, c2.width, c2.height);
            // スキャンライン
            cx2.globalCompositeOperation = 'source-over';
            cx2.globalAlpha = 0.18;
            cx2.fillStyle = accentHex;
            for (let y = 0; y < c2.height; y += 4) cx2.fillRect(0, y, c2.width, 1);
            cx2.globalAlpha = 1;
            const photoTex = new THREE.CanvasTexture(c2);
            if ('colorSpace' in photoTex) photoTex.colorSpace = THREE.SRGBColorSpace;
            figMat.map = photoTex;
            figMat.transparent = true;
            figMat.opacity = 0.92;
            figMat.needsUpdate = true;
            // procedural アニメから外す
            const idx = animatedTextures.indexOf(animEntry);
            if (idx >= 0) animatedTextures.splice(idx, 1);
          }).catch(() => {/* 画像なし → procedural のまま */});
        }
        // ラベル板（台座の前面に大きな名前 — ビルボード）
        const labelCanvas = document.createElement('canvas');
        labelCanvas.width = 512; labelCanvas.height = 160;
        const lg = labelCanvas.getContext('2d');
        // 名前の背景: 立派な銘板
        const labelGrd = lg.createLinearGradient(0, 0, 0, 160);
        labelGrd.addColorStop(0, '#2a1838'); labelGrd.addColorStop(1, '#0a0418');
        lg.fillStyle = labelGrd; lg.fillRect(0, 0, 512, 160);
        // 縁（accentHex は外スコープで定義済み）
        lg.strokeStyle = accentHex; lg.lineWidth = 4;
        lg.strokeRect(8, 8, 496, 144);
        lg.lineWidth = 1; lg.strokeStyle = accentHex + 'aa';
        lg.strokeRect(16, 16, 480, 128);
        // 大きな名前
        lg.fillStyle = accentHex;
        lg.font = 'bold 48px "Shippori Mincho", serif';
        lg.textAlign = 'center'; lg.textBaseline = 'middle';
        lg.shadowColor = '#000'; lg.shadowBlur = 6;
        lg.fillText(item.name, 256, 70);
        // サブタイトル
        lg.shadowBlur = 0;
        lg.fillStyle = '#e8d8ff';
        lg.font = '22px "Shippori Mincho", serif';
        lg.fillText(item.sub, 256, 120);
        const labelTex = new THREE.CanvasTexture(labelCanvas);
        if ('colorSpace' in labelTex) labelTex.colorSpace = THREE.SRGBColorSpace;
        const label = new THREE.Mesh(
          new THREE.PlaneGeometry(2.4, 0.75),
          new THREE.MeshBasicMaterial({ map: labelTex, transparent: true, side: THREE.DoubleSide })
        );
        label.position.y = 0.55;
        label.userData.isLabel = true; // animate でカメラ向きにする
        group.add(label);

        group.userData = { item, holo, ring, figure };
        plinths.push(group);
        scene.add(group);
      });

      // 🪨 入口前の石板 — ギリシャ神殿の正面プレートで案内するため無効化
      if (false && zone !== 'hub' && PANTHEON_DATA[zone]) {
        const accentHex = '#' + PANTHEON_DATA[zone].accent.toString(16).padStart(6, '0');
        const myth = PANTHEON_DATA[zone];
        const introTexts = [
          { title: myth.name, sub: myth.emoji + '   神 々', body: '入口より\n奥へ進めば\n神々と出会う' },
          { title: '案 内', sub: '— Hierarch —', body: `中央奥に\n${myth.name}を\n統べる神` },
        ];
        introTexts.forEach((info, i) => {
          const tablet = new THREE.Group();
          // 石板本体（傾斜した石碑）
          const stone = new THREE.Mesh(
            new THREE.BoxGeometry(2.0, 2.6, 0.25),
            new THREE.MeshStandardMaterial({ color: 0x8a7a98, roughness: 0.85, metalness: 0.1 })
          );
          stone.position.y = 1.5;
          tablet.add(stone);
          // 石の台座
          const tabBase = new THREE.Mesh(
            new THREE.BoxGeometry(2.4, 0.4, 0.6),
            new THREE.MeshStandardMaterial({ color: 0x5a4a68, roughness: 0.85 })
          );
          tabBase.position.y = 0.2;
          tablet.add(tabBase);
          // 文字テクスチャ
          const tc = document.createElement('canvas'); tc.width = 384; tc.height = 512;
          const tg = tc.getContext('2d');
          // 石の質感
          const grd = tg.createLinearGradient(0, 0, 0, 512);
          grd.addColorStop(0, '#a89aac'); grd.addColorStop(1, '#6a5a78');
          tg.fillStyle = grd; tg.fillRect(0, 0, 384, 512);
          // ノイズ
          for (let n = 0; n < 1200; n++) {
            tg.fillStyle = `rgba(0,0,0,${0.04+Math.random()*0.08})`;
            tg.fillRect(Math.random()*384, Math.random()*512, 1, 1);
          }
          // 縁飾り
          tg.strokeStyle = accentHex; tg.lineWidth = 4;
          tg.strokeRect(20, 20, 344, 472);
          // タイトル
          tg.font = 'bold 50px "Shippori Mincho", serif';
          tg.fillStyle = '#1a0a04';
          tg.textAlign = 'center';
          tg.shadowColor = 'rgba(0,0,0,0.4)'; tg.shadowBlur = 4;
          tg.fillText(info.title, 192, 100);
          tg.shadowBlur = 0;
          // セパレーター
          tg.strokeStyle = accentHex; tg.lineWidth = 2;
          tg.beginPath(); tg.moveTo(80, 140); tg.lineTo(304, 140); tg.stroke();
          // サブタイトル
          tg.font = 'italic 24px "Cormorant Garamond", "Shippori Mincho", serif';
          tg.fillStyle = accentHex;
          tg.fillText(info.sub, 192, 180);
          // 本文（石に刻まれた文字風）
          tg.font = '28px "Shippori Mincho", serif';
          tg.fillStyle = '#2a1a08';
          tg.shadowColor = 'rgba(255,255,255,0.3)'; tg.shadowBlur = 1; tg.shadowOffsetY = 1;
          info.body.split('\n').forEach((line, li) => {
            tg.fillText(line, 192, 260 + li * 50);
          });
          tg.shadowBlur = 0;
          // 装飾紋章
          tg.font = '32px serif';
          tg.fillStyle = accentHex;
          tg.fillText('❦', 192, 460);
          const tabTex = new THREE.CanvasTexture(tc);
          if ('colorSpace' in tabTex) tabTex.colorSpace = THREE.SRGBColorSpace;
          const inscription = new THREE.Mesh(
            new THREE.PlaneGeometry(1.7, 2.3),
            new THREE.MeshStandardMaterial({ map: tabTex, transparent: true, roughness: 0.85, side: THREE.DoubleSide })
          );
          inscription.position.set(0, 1.5, 0.13);
          tablet.add(inscription);
          // 石板の上の装飾燭台
          const candle = new THREE.Mesh(
            new THREE.SphereGeometry(0.08, 10, 8),
            new THREE.MeshBasicMaterial({ color: 0xfff4a0 })
          );
          candle.position.set(0, 3.0, 0);
          tablet.add(candle);
          const candleLight = new THREE.PointLight(0xffd890, 1.0, 5, 1.5);
          candleLight.position.set(0, 3.0, 0);
          tablet.add(candleLight);
          // 入口寄り（z=10）に左右配置
          const tx = i === 0 ? -3.5 : 3.5;
          tablet.position.set(tx, 0, 10);
          // 中央を向く
          tablet.lookAt(0, 1.5, 0);
          scene.add(tablet);
        });
      }

      // 🔮 神様の記憶 — 台座の上の球体（タップで関連3Dシーンへ吸い込まれる）
      const MEMORY_ORBS = {
        genesis: [
          { id:'eden', label:'エデンの園', sub:'始まりの庭', color:0x80c890, action:()=>window.openEden3D && window.openEden3D() },
          { id:'babel', label:'バベルの塔', sub:'天への塔', color:0xc8a060, action:()=>window.openBabel3D && window.openBabel3D() },
          { id:'noah', label:'ノアの箱舟', sub:'大洪水の記憶', color:0x6090c0, action:()=>window.openNoahArk3D && window.openNoahArk3D() },
        ],
        greek: [
          { id:'atlantis', label:'アトランティス', sub:'海に沈んだ都', color:0x4080c0, action:()=>window.openAtlantis3D && window.openAtlantis3D() },
          { id:'elysion', label:'エリュシオン', sub:'英雄の楽園', color:0xffd890, action:()=>window.openElysion3D && window.openElysion3D() },
        ],
      };
      const orbs = MEMORY_ORBS[zone] || [];
      orbs.forEach((mem, i) => {
        const og = new THREE.Group();
        // 石の台座（小さめ）
        const oBase = new THREE.Mesh(
          new THREE.CylinderGeometry(0.55, 0.7, 0.4, 16),
          new THREE.MeshStandardMaterial({ color: 0x8a7a98, roughness: 0.85 })
        );
        oBase.position.y = 0.2;
        og.add(oBase);
        const oTop = new THREE.Mesh(
          new THREE.CylinderGeometry(0.45, 0.55, 0.6, 16),
          new THREE.MeshStandardMaterial({ color: 0xa890b8, roughness: 0.7, metalness: 0.2 })
        );
        oTop.position.y = 0.7;
        og.add(oTop);
        // 金の縁
        const oRim = new THREE.Mesh(
          new THREE.TorusGeometry(0.45, 0.03, 8, 18),
          new THREE.MeshStandardMaterial({ color: 0xe8c060, roughness: 0.3, metalness: 0.85, emissive: 0x4a3008, emissiveIntensity: 0.5 })
        );
        oRim.rotation.x = Math.PI / 2;
        oRim.position.y = 1.0;
        og.add(oRim);
        // 🔮 記憶の球体（半透明、内側に光）
        const orb = new THREE.Mesh(
          new THREE.SphereGeometry(0.4, 24, 18),
          new THREE.MeshPhysicalMaterial({
            color: mem.color, transparent: true, opacity: 0.55,
            roughness: 0.0, transmission: 0.7, thickness: 0.5,
            emissive: new THREE.Color(mem.color), emissiveIntensity: 0.4,
            envMapIntensity: 1.5,
          })
        );
        orb.position.y = 1.5;
        og.add(orb);
        // 内側のコア（明るい光）
        const core = new THREE.Mesh(
          new THREE.SphereGeometry(0.18, 16, 12),
          new THREE.MeshBasicMaterial({ color: mem.color })
        );
        core.position.y = 1.5;
        og.add(core);
        // 周囲の発光（Sprite）
        const haloC = (() => {
          const c = document.createElement('canvas'); c.width = 128; c.height = 128;
          const cg = c.getContext('2d');
          const grd = cg.createRadialGradient(64, 64, 0, 64, 64, 64);
          const hex = '#' + mem.color.toString(16).padStart(6, '0');
          grd.addColorStop(0, hex + 'cc');
          grd.addColorStop(1, hex + '00');
          cg.fillStyle = grd; cg.fillRect(0, 0, 128, 128);
          return new THREE.CanvasTexture(c);
        })();
        const halo = new THREE.Sprite(new THREE.SpriteMaterial({
          map: haloC, transparent: true, opacity: 0.6,
          depthWrite: false, blending: THREE.AdditiveBlending,
        }));
        halo.scale.set(2.0, 2.0, 1);
        halo.position.y = 1.5;
        og.add(halo);
        // 内部光源
        const orbLight = new THREE.PointLight(mem.color, 1.5, 5, 1.5);
        orbLight.position.y = 1.5;
        og.add(orbLight);
        // 配置: 入口側 z=10〜13、x はオーブ数で分散
        const oN = orbs.length;
        const ox = oN === 1 ? 0 : (-6 + (12 / (oN - 1)) * i);
        og.position.set(ox, 0, 11);
        // userData (タップで起動)
        og.userData = {
          item: { type: 'memory', name: mem.label, sub: mem.sub, accent: mem.color },
          isMemory: true, memAction: mem.action,
          orb, core, halo,
        };
        scene.add(og);
        plinths.push(og); // 既存の最寄り判定システムに乗せる
      });

      // 各神話部屋の中央に「神話を読む」看板（hub では出さない）
      if (zone !== 'hub' && PANTHEON_DATA[zone]) {
        const tk = MYTH_STORY_KEY_MAP[zone];
        if (tk && window.MYTH_STORIES && window.MYTH_STORIES[tk] || tk) {
          const sign = new THREE.Group();
          sign.position.set(0, 0, 6.5); // 入口寄り（参道の前方）
          // 石の台座
          const stone = new THREE.Mesh(
            new THREE.CylinderGeometry(0.9, 1.1, 0.5, 16),
            new THREE.MeshStandardMaterial({ color: 0x6a5a78, roughness: 0.7, metalness: 0.2 })
          );
          stone.position.y = 0.25;
          sign.add(stone);
          // 看板（縦長プレート）
          const accentHex = '#' + PANTHEON_DATA[zone].accent.toString(16).padStart(6, '0');
          const cv = document.createElement('canvas');
          cv.width = 256; cv.height = 384;
          const ctx = cv.getContext('2d');
          // 古文書風背景
          const grd = ctx.createLinearGradient(0, 0, 0, 384);
          grd.addColorStop(0, '#3a2a1a'); grd.addColorStop(1, '#1a1008');
          ctx.fillStyle = grd; ctx.fillRect(0, 0, 256, 384);
          // 装飾枠
          ctx.strokeStyle = accentHex; ctx.lineWidth = 4;
          ctx.strokeRect(16, 16, 224, 352);
          ctx.lineWidth = 1;
          ctx.strokeRect(24, 24, 208, 336);
          // タイトル
          ctx.font = 'bold 28px "Shippori Mincho", serif';
          ctx.textAlign = 'center'; ctx.fillStyle = accentHex;
          ctx.shadowColor = '#000'; ctx.shadowBlur = 4;
          ctx.fillText(PANTHEON_DATA[zone].name, 128, 80);
          // 神話絵文字
          ctx.font = '90px serif';
          ctx.fillStyle = '#fff';
          ctx.shadowColor = accentHex; ctx.shadowBlur = 18;
          ctx.fillText(PANTHEON_DATA[zone].emoji, 128, 200);
          ctx.shadowBlur = 0;
          // サブタイトル
          ctx.font = '14px "Shippori Mincho", serif';
          ctx.fillStyle = '#e8d8b0';
          ctx.shadowColor = '#000'; ctx.shadowBlur = 4;
          ctx.fillText('— 神話を読む —', 128, 250);
          // 触れる印
          ctx.fillStyle = accentHex;
          ctx.font = 'bold 20px "Shippori Mincho", serif';
          ctx.fillText('▶ 物語を開く', 128, 320);
          ctx.fillStyle = '#a89878';
          ctx.font = '10px serif';
          ctx.fillText('近づいて選ぶ', 128, 345);
          const signTex = new THREE.CanvasTexture(cv);
          if ('colorSpace' in signTex) signTex.colorSpace = THREE.SRGBColorSpace;
          const board = new THREE.Mesh(
            new THREE.PlaneGeometry(2.0, 3.0),
            new THREE.MeshBasicMaterial({ map: signTex, transparent: true, side: THREE.DoubleSide })
          );
          board.position.y = 2.0;
          sign.add(board);
          // 看板の縁を木材で
          const frameMat = new THREE.MeshStandardMaterial({ color: 0x4a3220, roughness: 0.9 });
          const frameTop = new THREE.Mesh(new THREE.BoxGeometry(2.2, 0.15, 0.2), frameMat);
          frameTop.position.y = 3.55;
          sign.add(frameTop);
          const frameBottom = new THREE.Mesh(new THREE.BoxGeometry(2.2, 0.15, 0.2), frameMat);
          frameBottom.position.y = 0.55;
          sign.add(frameBottom);
          // 看板を「触れる」item として登録（plinth として扱う）
          sign.userData = {
            item: { type: 'tale', name: PANTHEON_DATA[zone].name + 'を読む', sub: '物語の章へ', talekey: tk, accent: PANTHEON_DATA[zone].accent },
            holo: stone, ring: stone, figure: board, // 共通インタフェース
          };
          scene.add(sign);
          plinths.push(sign);
        }
      }

      // 👻 HUB: 魂（プレイヤーアバター）— 半透明の発光球＋粒子
      if (zone === 'hub') {
        const soul = new THREE.Group();
        // 内側コア
        const core = new THREE.Mesh(
          new THREE.SphereGeometry(0.18, 16, 12),
          new THREE.MeshBasicMaterial({ color: 0xfff0e0, transparent: true, opacity: 0.95 })
        );
        soul.add(core);
        // 中間層
        const mid = new THREE.Mesh(
          new THREE.SphereGeometry(0.32, 16, 12),
          new THREE.MeshBasicMaterial({ color: 0xa0c8ff, transparent: true, opacity: 0.5, depthWrite: false, blending: THREE.AdditiveBlending })
        );
        soul.add(mid);
        // 外殻オーラ
        const auraTex = (() => {
          const c = document.createElement('canvas'); c.width = 256; c.height = 256;
          const g = c.getContext('2d');
          const grd = g.createRadialGradient(128, 128, 0, 128, 128, 128);
          grd.addColorStop(0, 'rgba(255,240,220,0.9)');
          grd.addColorStop(0.4, 'rgba(180,200,255,0.4)');
          grd.addColorStop(1, 'rgba(80,100,180,0)');
          g.fillStyle = grd; g.fillRect(0, 0, 256, 256);
          return new THREE.CanvasTexture(c);
        })();
        const aura = new THREE.Sprite(new THREE.SpriteMaterial({
          map: auraTex, color: 0xffffff,
          transparent: true, opacity: 0.85,
          depthWrite: false, blending: THREE.AdditiveBlending,
        }));
        aura.scale.set(2.0, 2.0, 1);
        soul.add(aura);
        // 自己発光（点光源）
        const soulLight = new THREE.PointLight(0xa0c8ff, 1.4, 8, 1.5);
        soul.add(soulLight);
        // 軌跡パーティクル
        // 🌟 軌跡: 高品質なスプライト光のリボン
        const dotTex = (() => {
          const c = document.createElement('canvas'); c.width = 128; c.height = 128;
          const g = c.getContext('2d');
          const grd = g.createRadialGradient(64, 64, 0, 64, 64, 64);
          grd.addColorStop(0, 'rgba(255,255,255,1)');
          grd.addColorStop(0.3, 'rgba(220,200,255,0.85)');
          grd.addColorStop(0.6, 'rgba(120,140,200,0.4)');
          grd.addColorStop(1, 'rgba(60,80,140,0)');
          g.fillStyle = grd; g.fillRect(0, 0, 128, 128);
          return new THREE.CanvasTexture(c);
        })();
        const TRAIL = 28;
        const trailDots = [];
        const trailMat = new THREE.SpriteMaterial({
          map: dotTex, color: 0xc8d8ff,
          transparent: true, opacity: 0.7,
          depthWrite: false, blending: THREE.AdditiveBlending, fog: false,
        });
        for (let i = 0; i < TRAIL; i++) {
          const d = new THREE.Sprite(trailMat.clone());
          // 後ろほど小さく薄く
          const f = 1 - (i / TRAIL);
          d.scale.set(0.45 * f, 0.45 * f, 1);
          d.material.opacity = 0.7 * f;
          d.position.set(0, 1.8, 0);
          // 各ドットの色を少しずつ揺らす（虹色の魂）
          const hue = (i * 14) % 360;
          d.userData = { age: 0, baseHue: hue };
          scene.add(d);
          trailDots.push(d);
        }
        const trail = { dots: trailDots, head: 0 };
        // 初期位置（中央、本のリングのすぐ内側）
        soul.position.set(0, 1.8, 0);
        scene.add(soul);
        scene.userData.soul = soul;
        scene.userData.soulCore = core;
        scene.userData.soulMid = mid;
        scene.userData.soulAura = aura;
        scene.userData.soulTrail = trail;
        scene.userData.zoomOutT = 0; // 0→1 でカメラがズームアウト
      }

      titleEl.textContent = zone === 'hub' ? '神 殿' : (PANTHEON_DATA[zone]?.name || '神 殿');
      backBtn.style.display = (zone === 'hub') ? 'none' : 'inline-block';
    }
    // 神殿zone → MYTH_STORIES key の対応
    const MYTH_STORY_KEY_MAP = {
      genesis: 'genesis', greek: 'greek', japan: 'japan',
      norse: 'norse', egypt: 'egypt', hindu: 'hindu',
      celtic: 'celtic', mesopotamia: 'mesopotamia', china: 'china', mesoamerica: 'mesoamerica',
    };

    // カメラ
    camera = new THREE.PerspectiveCamera(70, W()/H(), 0.1, 200);
    camera.position.set(0, 1.6, 0);

    buildScene('hub');

    // 👁 目を開く（裏でシーン構築完了）— ゆっくり 2.2s
    requestAnimationFrame(() => {
      blink.classList.remove('closing');
      blink.classList.add('opening');
      setTimeout(() => blink.remove(), 2300);
    });

    // 入力
    window.addEventListener('keydown', e => {
      if (!ov.classList.contains('open')) return;
      const k = e.key.toLowerCase();
      if (k === 'w' || e.key === 'ArrowUp') keys.w = 1;
      if (k === 's' || e.key === 'ArrowDown') keys.s = 1;
      if (k === 'a' || e.key === 'ArrowLeft') keys.a = 1;
      if (k === 'd' || e.key === 'ArrowRight') keys.d = 1;
    });
    window.addEventListener('keyup', e => {
      const k = e.key.toLowerCase();
      if (k === 'w' || e.key === 'ArrowUp') keys.w = 0;
      if (k === 's' || e.key === 'ArrowDown') keys.s = 0;
      if (k === 'a' || e.key === 'ArrowLeft') keys.a = 0;
      if (k === 'd' || e.key === 'ArrowRight') keys.d = 0;
    });
    let dragging = false, lastX = 0, lastY = 0;
    renderer.domElement.addEventListener('pointerdown', e => { dragging = true; lastX = e.clientX; lastY = e.clientY; });
    renderer.domElement.addEventListener('pointermove', e => {
      if (!dragging) return;
      // 原神方式：ドラッグ右→視線も右へ
      yaw += (e.clientX - lastX) * 0.0075;
      pitch = Math.max(-1.45, Math.min(1.45, pitch - (e.clientY - lastY) * 0.0065));
      lastX = e.clientX; lastY = e.clientY;
    });
    renderer.domElement.addEventListener('pointerup', () => dragging = false);
    renderer.domElement.addEventListener('pointercancel', () => dragging = false);
    renderer.domElement.addEventListener('pointerleave', () => dragging = false);
    // モバイル: スティック
    const stick = ov.querySelector('#ptStick');
    const knob = ov.querySelector('#ptKnob');
    let stickActive = false;
    const stickStart = e => {
      stickActive = true;
      const t = e.touches ? e.touches[0] : e;
      stick.dataset.cx = t.clientX; stick.dataset.cy = t.clientY;
      stickDX = stickDY = 0; e.preventDefault();
    };
    const stickMove = e => {
      if (!stickActive) return;
      const t = e.touches ? e.touches[0] : e;
      const cx = +stick.dataset.cx, cy = +stick.dataset.cy;
      let dx = t.clientX - cx, dy = t.clientY - cy;
      const d = Math.hypot(dx, dy);
      const MAX = 40;
      if (d > MAX) { dx = dx/d*MAX; dy = dy/d*MAX; }
      knob.style.transform = `translate(${dx}px, ${dy}px)`;
      stickDX = dx / MAX; stickDY = dy / MAX;
      e.preventDefault();
    };
    const stickEnd = () => { stickActive = false; knob.style.transform = 'translate(0,0)'; stickDX = stickDY = 0; };
    stick.addEventListener('touchstart', stickStart, { passive: false });
    stick.addEventListener('touchmove', stickMove, { passive: false });
    stick.addEventListener('touchend', stickEnd);

    enterBtn.addEventListener('click', () => {
      if (!currentNear) return;
      const item = currentNear.userData.item;
      if (item.type === 'pantheon') {
        currentZone = item.key;
        buildScene(item.key);
        // 🚪 入口（南側）から神殿に入った視点で配置
        // ringR=12 で台座が円形配置 → 入口は z=14 付近、奥（中心側）を見る
        camera.position.set(0, 1.6, 12); yaw = 0; // 神殿の前列柱間から、奥の主神を見る
      } else if (item.type === 'god') {
        summonGod(item, currentZone); // 召喚演出 → モーダル
      } else if (item.type === 'tale') {
        if (window.openMythology) window.openMythology(item.talekey);
      } else if (item.type === 'memory') {
        // 🔮 神様の記憶: フラッシュ → 関連3Dシーンへ
        const memG = currentNear;
        const flash = document.createElement('div');
        flash.style.cssText = 'position:fixed;inset:0;background:#fff;opacity:0;z-index:25000;pointer-events:none;transition:opacity 0.5s';
        document.body.appendChild(flash);
        requestAnimationFrame(() => flash.style.opacity = '1');
        setTimeout(() => {
          try { memG.userData.memAction && memG.userData.memAction(); } catch (e) { console.warn('memory dive', e); }
          flash.style.opacity = '0';
          setTimeout(() => flash.remove(), 600);
        }, 500);
      }
    });
    backBtn.addEventListener('click', () => {
      currentZone = 'hub';
      buildScene('hub');
      camera.position.set(0, 1.6, 0); yaw = 0;
    });

    // 🌟 召喚演出（グラブル風カットイン）→ その後 showGodModal
    function summonGod(god, zoneKey) {
      const accentHex = '#' + (god.accent || 0x9080d0).toString(16).padStart(6, '0');
      const sm = document.createElement('div');
      sm.className = 'god-summon';
      sm.style.setProperty('--acc', accentHex);
      sm.innerHTML = `
        <div class="gs-flash"></div>
        <div class="gs-circle">
          <svg class="gs-circle-svg" viewBox="0 0 400 400">
            <circle cx="200" cy="200" r="180" fill="none" stroke="${accentHex}" stroke-width="2" stroke-dasharray="6 4"/>
            <circle cx="200" cy="200" r="150" fill="none" stroke="${accentHex}" stroke-width="1.5"/>
            <circle cx="200" cy="200" r="120" fill="none" stroke="${accentHex}" stroke-width="1"/>
            <g class="gs-pent" stroke="${accentHex}" stroke-width="2" fill="none">
              ${[0,1,2,3,4].map(i => {
                const a1 = (i/5)*Math.PI*2 - Math.PI/2;
                const a2 = ((i+2)/5)*Math.PI*2 - Math.PI/2;
                return `<line x1="${200+Math.cos(a1)*150}" y1="${200+Math.sin(a1)*150}" x2="${200+Math.cos(a2)*150}" y2="${200+Math.sin(a2)*150}"/>`;
              }).join('')}
            </g>
            <text x="200" y="210" text-anchor="middle" font-size="72" fill="${accentHex}" font-family="serif">${PANTHEON_DATA[zoneKey]?.emoji || '✦'}</text>
          </svg>
        </div>
        <div class="gs-particles">
          ${Array.from({length: 24}).map((_, i) => `<div class="gs-particle" style="--i:${i};--acc:${accentHex}"></div>`).join('')}
        </div>
        <div class="gs-rays">
          ${Array.from({length: 12}).map((_, i) => `<div class="gs-ray" style="--r:${i*30}deg;--acc:${accentHex}"></div>`).join('')}
        </div>
        <div class="gs-name-eyebrow">— S U M M O N —</div>
        <div class="gs-name">${god.name}</div>
        <div class="gs-sub">${god.sub || ''}</div>
      `;
      ov.appendChild(sm);
      requestAnimationFrame(() => sm.classList.add('go'));
      // 1.6秒後に通常モーダルへ
      setTimeout(() => {
        sm.classList.add('fade');
        setTimeout(() => sm.remove(), 500);
        showGodModal(god, zoneKey);
      }, 1700);
    }

    function showGodModal(god, zoneKey) {
      // god is the userData.item: { type:'god', name, sub, img, lore, accent }
      const m = document.createElement('div');
      m.className = 'pantheon-modal';
      const accentHex = '#' + (god.accent || 0x9080d0).toString(16).padStart(6, '0');
      // プレースホルダSVG（即時表示）
      const placeholderSVG = `data:image/svg+xml;utf8,${encodeURIComponent(`<svg xmlns="http://www.w3.org/2000/svg" width="240" height="320"><defs><linearGradient id="g" x1="0" x2="0" y1="0" y2="1"><stop offset="0" stop-color="#3a2050"/><stop offset="1" stop-color="#0a0418"/></linearGradient></defs><rect width="240" height="320" fill="url(#g)"/><text x="120" y="180" text-anchor="middle" fill="${accentHex}" font-size="72" font-family="serif">✦</text><text x="120" y="240" text-anchor="middle" fill="#fff" font-size="18" font-family="serif">${(god.name||'').slice(0,8)}</text></svg>`)}`;
      m.innerHTML = `
        <div class="pm-card">
          <button class="pm-close">×</button>
          <img class="pm-img" alt="${god.name}" src="${placeholderSVG}">
          <div class="pm-body">
            <div class="pm-sub">${god.sub || ''}</div>
            <div class="pm-name">${god.name || '神'}</div>
            <div class="pm-lore">${god.lore || ''}</div>
            <div class="pm-zone">— ${PANTHEON_DATA[zoneKey]?.name || ''} —</div>
          </div>
        </div>
      `;
      ov.appendChild(m);
      requestAnimationFrame(() => m.classList.add('show'));
      const close = () => { m.classList.remove('show'); setTimeout(() => m.remove(), 300); };
      m.querySelector('.pm-close').addEventListener('click', close);
      m.addEventListener('click', e => { if (e.target === m) close(); });
      // 🖼 Wikimedia API で正確なサムネイルURLを解決（CORS安全）
      if (god.img) {
        const imgEl = m.querySelector('.pm-img');
        const filenameMatch = god.img.match(/Special:FilePath\/([^?]+)/);
        if (filenameMatch) {
          const filename = decodeURIComponent(filenameMatch[1]).replace(/_/g, ' ');
          const api = `https://commons.wikimedia.org/w/api.php?action=query&format=json&prop=imageinfo&iiprop=url&iiurlwidth=600&titles=${encodeURIComponent('File:' + filename)}&origin=*`;
          fetch(api).then(r => r.json()).then(d => {
            const pages = d.query?.pages || {};
            const p = Object.values(pages)[0];
            const thumb = p?.imageinfo?.[0]?.thumburl;
            if (thumb && imgEl) imgEl.src = thumb;
          }).catch(() => {});
        }
      }
    }

    let running = true;
    ov.querySelector('.museum3d-close').addEventListener('click', () => {
      running = false;
      ov.classList.remove('open');
      setTimeout(() => {
        // 🧹 シーン・レンダラーの完全破棄（背景バグ防止）
        try {
          scene.traverse(o => {
            if (o.geometry) o.geometry.dispose && o.geometry.dispose();
            if (o.material) {
              const mats = Array.isArray(o.material) ? o.material : [o.material];
              mats.forEach(m => {
                if (m.map) m.map.dispose && m.map.dispose();
                m.dispose && m.dispose();
              });
            }
          });
          if (scene.environment) scene.environment.dispose && scene.environment.dispose();
          renderer.dispose();
          renderer.forceContextLoss && renderer.forceContextLoss();
          renderer.domElement.parentNode && renderer.domElement.parentNode.removeChild(renderer.domElement);
        } catch (e) { console.warn('cleanup', e); }
        ov.remove();
      }, 500);
    });

    let t = 0;
    function animate() {
      if (!running) return;
      if (document.hidden) { requestAnimationFrame(animate); return; }
      t += 0.016;
      // ╔═══════════════════════════════════════════╗
      // ║ HUB は魂の操作 + 三人称カメラ              ║
      // ║ ゾーン内は従来の歩行（カメラ直接操作）       ║
      // ╚═══════════════════════════════════════════╝
      const soul = scene.userData.soul;
      if (soul) {
        // 🌟 魂の移動（原神方式：カメラ実方向ベース）
        const speed = 0.13;
        const fwd = (keys.w - keys.s) - stickDY;
        const strafe = (keys.d - keys.a) + stickDX;
        const moveLen = Math.hypot(fwd, strafe);
        if (moveLen > 0) {
          const f = fwd / moveLen;
          const s = strafe / moveLen;
          const fx = Math.sin(yaw), fz = -Math.cos(yaw);
          const rx = Math.cos(yaw), rz = Math.sin(yaw);
          soul.position.x += (fx * f + rx * s) * speed;
          soul.position.z += (fz * f + rz * s) * speed;
        }
        // 半径22内に制限（本のリングは半径12）
        const sd = Math.hypot(soul.position.x, soul.position.z);
        if (sd > 22) {
          soul.position.x = soul.position.x / sd * 22;
          soul.position.z = soul.position.z / sd * 22;
        }
        // 魂の脈動
        const pulse = 1 + Math.sin(t * 2.4) * 0.12;
        if (scene.userData.soulCore) scene.userData.soulCore.scale.setScalar(pulse);
        if (scene.userData.soulMid) scene.userData.soulMid.scale.setScalar(pulse * 1.05);
        if (scene.userData.soulAura) {
          const auraS = 2.0 + Math.sin(t * 1.5) * 0.4;
          scene.userData.soulAura.scale.set(auraS, auraS, 1);
          scene.userData.soulAura.material.opacity = 0.7 + Math.sin(t * 1.8) * 0.2;
        }
        // 🌟 軌跡更新（スプライトリボン式）
        if (scene.userData.soulTrail && scene.userData.soulTrail.dots) {
          const tr = scene.userData.soulTrail;
          // 5フレームに1回だけ新しい点を打つ（重複防止）
          tr.head = (tr.head + 1) % tr.dots.length;
          const head = tr.dots[tr.head];
          head.position.set(
            soul.position.x + (Math.random()-0.5) * 0.05,
            soul.position.y + (Math.random()-0.5) * 0.05,
            soul.position.z + (Math.random()-0.5) * 0.05
          );
          head.userData.age = 0;
          // 全ドットを年齢に応じてフェードアウト
          tr.dots.forEach((d, i) => {
            d.userData.age += 0.016;
            const a = d.userData.age;
            const fade = Math.max(0, 1 - a * 0.5); // 約2秒で消える
            d.material.opacity = fade * 0.85;
            const s = 0.45 * fade;
            d.scale.set(s, s, 1);
            // ふわふわと上昇 + 横ゆらぎ
            d.position.y += 0.005;
            d.position.x += Math.sin(a * 4 + i) * 0.003;
          });
        }
        // カメラ: 三人称（魂の後ろ上から） + 初期ズームアウト演出
        scene.userData.zoomOutT = Math.min(1, scene.userData.zoomOutT + 0.012);
        const zo = scene.userData.zoomOutT;
        const easeOut = 1 - Math.pow(1 - zo, 3);
        // 距離: 0.3 (顔のすぐ後ろ) → 5 (三人称)
        const camDist = 0.3 + easeOut * 4.7;
        const camHeight = 0.0 + easeOut * 1.8;
        // カメラ位置: 魂から後方へ
        const bx = -Math.sin(yaw), bz = Math.cos(yaw);
        camera.position.set(
          soul.position.x + bx * camDist,
          soul.position.y + camHeight,
          soul.position.z + bz * camDist
        );
        // 視線: 魂を見つめながら yaw/pitch 方向を加算
        camera.lookAt(
          soul.position.x + Math.sin(yaw) * Math.cos(pitch) * 5,
          soul.position.y + Math.sin(pitch) * 3,
          soul.position.z - Math.cos(yaw) * Math.cos(pitch) * 5
        );
      } else {
        // 神殿内ゾーン歩行（原神方式：カメラ実方向ベース）
        const speed = 0.10;
        const fwd = (keys.w - keys.s) - stickDY;
        const strafe = (keys.d - keys.a) + stickDX;
        const moveLen = Math.hypot(fwd, strafe);
        if (moveLen > 0) {
          const f = fwd / moveLen;
          const s = strafe / moveLen;
          const fx = Math.sin(yaw), fz = -Math.cos(yaw);
          const rx = Math.cos(yaw), rz = Math.sin(yaw);
          camera.position.x += (fx * f + rx * s) * speed;
          camera.position.z += (fz * f + rz * s) * speed;
          const d = Math.hypot(camera.position.x, camera.position.z);
          if (d > 18) {
            camera.position.x = camera.position.x / d * 18;
            camera.position.z = camera.position.z / d * 18;
          }
        }
        camera.lookAt(
          camera.position.x + Math.sin(yaw) * Math.cos(pitch) * 5,
          camera.position.y + Math.sin(pitch) * 5,
          camera.position.z - Math.cos(yaw) * Math.cos(pitch) * 5
        );
      }
      // 🎨 動くSVG/Canvas（神話別のシンボル / 神の顔）
      if (Math.floor(t * 60) % 3 === 0) {
        animatedTextures.forEach(a => {
          const ctx = a.ctx;
          const W2 = 384, H2 = 480;
          ctx.clearRect(0, 0, W2, H2);
          // 背景: 神聖な放射グラデ
          const cy = 240;
          const cx = 192;
          // ハブの神話タイル → 神話別シンボル画
          if (a.item.type === 'pantheon') {
            drawPantheonSymbol(ctx, W2, H2, cx, cy, t, a.item.key, a.accent);
            // 名前プレート
            ctx.fillStyle = 'rgba(20,10,30,0.88)';
            ctx.fillRect(30, H2 - 70, W2 - 60, 50);
            ctx.strokeStyle = a.accent; ctx.lineWidth = 2;
            ctx.strokeRect(30, H2 - 70, W2 - 60, 50);
            ctx.font = 'bold 28px "Shippori Mincho", serif';
            ctx.textAlign = 'center'; ctx.textBaseline = 'middle';
            ctx.fillStyle = a.accent;
            ctx.shadowColor = '#000'; ctx.shadowBlur = 4;
            ctx.fillText(a.item.name, cx, H2 - 45);
            ctx.shadowBlur = 0;
            a.tex.needsUpdate = true;
            return; // 顔シルエット描画はスキップ
          }
          const bg = ctx.createLinearGradient(0, 0, 0, H2);
          bg.addColorStop(0, '#0a0418');
          bg.addColorStop(0.5, a.accent + '40');
          bg.addColorStop(1, '#0a0418');
          ctx.fillStyle = bg; ctx.fillRect(0, 0, W2, H2);
          // 後ろの曼荼羅（回転）
          ctx.save();
          ctx.translate(cx, cy);
          ctx.rotate(t * 0.15);
          ctx.strokeStyle = a.accent + '99';
          ctx.lineWidth = 1.5;
          for (let petal = 0; petal < 8; petal++) {
            ctx.save();
            ctx.rotate((petal / 8) * Math.PI * 2);
            ctx.beginPath();
            ctx.moveTo(0, 0);
            ctx.bezierCurveTo(35, -25, 35, -75, 0, -90);
            ctx.bezierCurveTo(-35, -75, -35, -25, 0, 0);
            ctx.stroke();
            ctx.restore();
          }
          ctx.restore();
          // 後光（中心から放射、 canvas に収まる長さ）
          ctx.save();
          ctx.translate(cx, cy - 40);
          ctx.rotate(-t * 0.1);
          for (let r = 0; r < 24; r++) {
            ctx.save();
            ctx.rotate((r / 24) * Math.PI * 2);
            ctx.fillStyle = a.accent + (r % 2 === 0 ? '60' : '30');
            ctx.beginPath();
            ctx.moveTo(0, -50);
            ctx.lineTo(3.5, -150);
            ctx.lineTo(-3.5, -150);
            ctx.closePath();
            ctx.fill();
            ctx.restore();
          }
          ctx.restore();
          // 神の顔（シルエット）
          ctx.save();
          ctx.translate(cx, cy - 50);
          // 髪/王冠（神話別）
          const headColor = a.accent;
          ctx.fillStyle = '#1a0a2a';
          // 顔の輪郭（楕円）
          ctx.beginPath();
          ctx.ellipse(0, 0, 36, 44, 0, 0, Math.PI * 2);
          ctx.fill();
          // 髪
          ctx.fillStyle = headColor + 'dd';
          ctx.beginPath();
          ctx.moveTo(-38, -10);
          ctx.bezierCurveTo(-44, -50, -20, -56, 0, -50);
          ctx.bezierCurveTo(20, -56, 44, -50, 38, -10);
          ctx.bezierCurveTo(34, -30, 0, -34, 0, -34);
          ctx.bezierCurveTo(0, -34, -34, -30, -38, -10);
          ctx.fill();
          // 王冠（神格を示す）
          ctx.fillStyle = '#fff8c0';
          ctx.shadowColor = headColor; ctx.shadowBlur = 12;
          ctx.beginPath();
          for (let i = 0; i < 5; i++) {
            const px = -24 + i * 12;
            ctx.moveTo(px, -42);
            ctx.lineTo(px + 4, -54);
            ctx.lineTo(px + 8, -42);
          }
          ctx.fill();
          ctx.shadowBlur = 0;
          // 目（光る）
          ctx.fillStyle = '#fff';
          ctx.beginPath();
          ctx.ellipse(-12, -2, 4, 5, 0, 0, Math.PI * 2);
          ctx.ellipse(12, -2, 4, 5, 0, 0, Math.PI * 2);
          ctx.fill();
          ctx.fillStyle = headColor;
          const blink = Math.sin(t * 0.7) > 0.95 ? 0.3 : 1;
          ctx.beginPath();
          ctx.ellipse(-12, -2, 2.2, 2.8 * blink, 0, 0, Math.PI * 2);
          ctx.ellipse(12, -2, 2.2, 2.8 * blink, 0, 0, Math.PI * 2);
          ctx.fill();
          // 鼻 + 口
          ctx.strokeStyle = '#1a0a2a'; ctx.lineWidth = 1.5;
          ctx.beginPath();
          ctx.moveTo(0, 5); ctx.lineTo(-2, 14);
          ctx.stroke();
          ctx.beginPath();
          ctx.arc(0, 22, 6, 0.2, Math.PI - 0.2);
          ctx.stroke();
          // 第三の眼（ヒンドゥー神話だけ）
          if (a.accent === '#ffb0a0') {
            ctx.fillStyle = '#ff4040';
            ctx.beginPath();
            ctx.ellipse(0, -22, 4, 2.5, 0, 0, Math.PI * 2);
            ctx.fill();
          }
          ctx.restore();
          // パルス粒（軌道を周回）
          for (let i = 0; i < 6; i++) {
            const ang = (i / 6) * Math.PI * 2 + t * 0.4;
            const dr = 130 + Math.sin(t * 2 + i) * 12;
            const px = cx + Math.cos(ang) * dr;
            const py = cy - 40 + Math.sin(ang) * dr * 0.7;
            ctx.fillStyle = a.accent;
            ctx.shadowColor = a.accent; ctx.shadowBlur = 12;
            ctx.beginPath(); ctx.arc(px, py, 3, 0, Math.PI * 2); ctx.fill();
            ctx.shadowBlur = 0;
          }
          // 名前プレート
          ctx.fillStyle = 'rgba(20,10,30,0.88)';
          ctx.fillRect(30, H2 - 70, W2 - 60, 50);
          ctx.strokeStyle = a.accent;
          ctx.lineWidth = 1.5;
          ctx.strokeRect(30, H2 - 70, W2 - 60, 50);
          ctx.font = 'bold 24px "Shippori Mincho", serif';
          ctx.textAlign = 'center'; ctx.textBaseline = 'middle';
          ctx.fillStyle = a.accent;
          ctx.fillText(a.item.name.slice(0, 8), cx, H2 - 45);
          a.tex.needsUpdate = true;
        });
      }
      // 🚗 車のヘッドライトが街を周回
      if (scene.userData.carData && scene.userData.cars) {
        const cd = scene.userData.carData;
        const pa = scene.userData.cars.geometry.attributes.position;
        for (let i = 0; i < cd.length; i++) {
          cd[i].angle += cd[i].speed;
          pa.array[i*3] = Math.cos(cd[i].angle) * cd[i].radius;
          pa.array[i*3+2] = Math.sin(cd[i].angle) * cd[i].radius;
        }
        pa.needsUpdate = true;
      }
      // 🚨 航空灯（赤beacon）の点滅
      const beaconOn = Math.floor(t * 1.2) % 2 === 0;
      scene.traverse(obj => {
        if (obj.userData && obj.userData.isBeacon && obj.material) {
          obj.material.color.setHex(beaconOn ? 0xff3040 : 0x401010);
        }
      });
      // 🔥 灯火のゆらぎアニメ
      if (scene.userData.torchFlames) {
        scene.userData.torchFlames.forEach((tf, i) => {
          const flick = 0.85 + Math.sin(t * 6 + i) * 0.15 + Math.random() * 0.1;
          tf.flame.scale.set(0.7 * flick, 1.4 * (1 + (1-flick)*0.3), 0.7 * flick);
          const haloS = tf.baseScale * (0.9 + (flick - 0.85) * 1.5);
          tf.halo.scale.set(haloS, haloS, 1);
          tf.halo.material.opacity = 0.55 + flick * 0.25;
          tf.light.intensity = tf.basePower * (0.85 + flick * 0.3);
        });
      }
      // ホログラム/本 アニメ
      plinths.forEach((p, idx) => {
        if (p.userData.isBook) {
          // 📖 浮かぶ本: ふわふわ漂う + ゆっくり回転 + カメラ向き調整
          const baseY = p.userData.baseY || 1.8;
          p.position.y = baseY + Math.sin(t * 0.6 + idx * 0.7) * 0.25;
          // 本がプレイヤーの方を向く（背表紙→表紙）
          if (p.userData.bookMesh) {
            const targetY = Math.atan2(camera.position.x - p.position.x, camera.position.z - p.position.z);
            p.userData.bookMesh.rotation.y += (targetY - p.userData.bookMesh.rotation.y) * 0.05;
            p.userData.bookMesh.rotation.x = Math.sin(t * 0.4 + idx) * 0.06;
          }
          // 後光脈動
          if (p.userData.halo) {
            p.userData.halo.material.opacity = 0.45 + Math.sin(t * 1.3 + idx * 0.6) * 0.15;
            const s = 7 + Math.sin(t * 0.8 + idx) * 0.4;
            p.userData.halo.scale.set(s, s, 1);
          }
          return;
        }
        if (p.userData.figure) p.userData.figure.lookAt(camera.position.x, p.userData.figure.getWorldPosition(new THREE.Vector3()).y, camera.position.z);
        if (p.userData.holo) p.userData.holo.rotation.y += 0.005;
        if (p.userData.magicCircle) p.userData.magicCircle.rotation.z += 0.003;
        if (p.userData.isMemory) {
          // 🔮 記憶のオーブ: 脈動 + ふわふわ + ゆっくり回転
          const pulse = 1 + Math.sin(t * 1.6 + p.position.x) * 0.08;
          if (p.userData.orb) {
            p.userData.orb.scale.setScalar(pulse);
            p.userData.orb.rotation.y += 0.008;
            p.userData.orb.position.y = 1.5 + Math.sin(t * 0.9 + p.position.x) * 0.1;
          }
          if (p.userData.core) {
            p.userData.core.position.y = p.userData.orb ? p.userData.orb.position.y : 1.5;
          }
          if (p.userData.halo) {
            const hs = 2.0 + Math.sin(t * 1.3) * 0.3;
            p.userData.halo.scale.set(hs, hs, 1);
            p.userData.halo.position.y = p.userData.orb ? p.userData.orb.position.y : 1.5;
          }
        }
        if (p.userData.ring && p.userData.ring.material) p.userData.ring.material.opacity = 0.4 + Math.sin(t * 2 + p.position.x) * 0.2;
        p.children.forEach(ch => {
          if (ch.userData && ch.userData.isLabel) {
            ch.lookAt(camera.position.x, ch.getWorldPosition(new THREE.Vector3()).y, camera.position.z);
          }
        });
      });
      // 最寄りの判定 — 魂モードは魂基準、それ以外はカメラ基準
      const probe = soul ? soul.position : camera.position;
      let best = null, bestD = soul ? 4 : 5;
      plinths.forEach(p => {
        const dx = p.position.x - probe.x;
        const dz = p.position.z - probe.z;
        const dist = Math.hypot(dx, dz);
        if (dist < bestD) {
          if (soul) {
            // 魂は方向に関係なく近さで判定
            best = p; bestD = dist;
          } else {
            const fx = Math.sin(yaw), fz = -Math.cos(yaw);
            const dot = (dx/dist) * fx + (dz/dist) * fz;
            if (dot > 0.4) { best = p; bestD = dist; }
          }
        }
      });
      // 魂が本に「ぶつかる」と自動でその神話に入る（一度きり、loop 継続）
      if (soul && best && bestD < 1.5 && !scene.userData.entering) {
        const it = best.userData.item;
        if (it.type === 'pantheon' && currentZone === 'hub') {
          scene.userData.entering = true; // 二重発火を防ぐ
          // フラッシュ演出（CSS のみ・要素を上に被せる）
          const flash = document.createElement('div');
          flash.style.cssText = 'position:fixed;inset:0;background:#fff;opacity:0;z-index:9998;pointer-events:none;transition:opacity 0.4s';
          document.body.appendChild(flash);
          requestAnimationFrame(() => flash.style.opacity = '1');
          setTimeout(() => {
            currentZone = it.key;
            try { buildScene(it.key); } catch (e) { console.warn('buildScene failed', e); }
            // 🚪 入口から神殿に入った視点
            camera.position.set(0, 1.6, 12); yaw = 0; // 神殿の前列柱間から、奥の主神を見る
            flash.style.opacity = '0';
            setTimeout(() => flash.remove(), 500);
          }, 450);
          // フラグ後はそのまま animate を続行（freeze 防止）
        }
      }
      if (best !== currentNear) {
        currentNear = best;
        if (best) {
          const it = best.userData.item;
          infoEl.innerHTML = `<div class="mv-info-name">${it.name}</div><div class="mv-info-sub">${it.sub}</div>`;
          infoEl.classList.add('show');
          enterBtn.classList.add('show');
          enterBtn.textContent = it.type === 'pantheon' ? (soul ? '🌟 魂で本に入る ›' : 'この神殿に入る ›')
            : it.type === 'tale' ? '物語を読む ›'
            : it.type === 'memory' ? '🔮 記憶に吸い込まれる ›'
            : '詳しく見る ›';
        } else {
          infoEl.classList.remove('show');
          enterBtn.classList.remove('show');
        }
      }
      renderer.render(scene, camera);
      requestAnimationFrame(animate);
    }
    animate();

    window.addEventListener('resize', () => {
      renderer.setSize(W(), H());
      camera.aspect = W()/H();
      camera.updateProjectionMatrix();
    });
  }
  window.openPantheon3D = openPantheon3D;

