          g.beginPath(); g.ellipse(240, 350, 100, 75, 0, 0, Math.PI*2); g.fill();
          g.beginPath(); g.ellipse(355, 305, 50, 48, 0, 0, Math.PI*2); g.fill();
          g.fillStyle = pal.dark;
          g.beginPath(); g.ellipse(398, 320, 18, 14, 0, 0, Math.PI*2); g.fill();
