          g.beginPath(); g.ellipse(300, 320, 32, 30, 0, 0, Math.PI*2); g.fill();
          g.fillStyle = pal.light;
          g.beginPath(); g.ellipse(310, 328, 14, 12, 0, 0, Math.PI*2); g.fill();
          g.fillStyle = pal.body;
