      const vGeo = new THREE.ExtrudeGeometry(vShape, { depth: 0.015, bevelEnabled: true, bevelSize: 0.003, bevelThickness: 0.003, bevelSegments: 1 });
      const vfin = new THREE.Mesh(vGeo, yellowMat);
      vfin.position.set(0, 0.08, 0.04);
