        const upperWingGeo = new THREE.ExtrudeGeometry(upperWingShape, { depth: 0.02, bevelEnabled: true, bevelSize: 0.004, bevelThickness: 0.004, bevelSegments: 1 });
        const upperWing = new THREE.Mesh(upperWingGeo, whiteMat);
